-- RPC upsert (SECURITY DEFINER) para registrar/actualizar aceptacion.
-- p_evaluation_id es nullable para coexistir con clientes viejos que
-- no envian evaluation_id (forward-compatible).
-- DROP previo de la firma vieja (6 params) para evitar overload:
-- CREATE OR REPLACE con firma distinta crea un nuevo signature en
-- vez de reemplazar, dejando dos funciones vivas y causando ambiguedad
-- al invocar por nombre.
DROP FUNCTION IF EXISTS public.record_acceptance(
  TEXT, BIGINT, TEXT, TEXT, TEXT, TEXT);

CREATE OR REPLACE FUNCTION public.record_acceptance(
  p_github_username TEXT,
  p_assignment_id BIGINT,
  p_assignment_title TEXT DEFAULT NULL,
  p_section TEXT DEFAULT NULL,
  p_repo_name TEXT DEFAULT NULL,
  p_repo_url TEXT DEFAULT NULL,
  p_evaluation_id BIGINT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.assignment_acceptances
    (github_username, assignment_id, assignment_title, section, repo_name, repo_url, evaluation_id, accepted_at)
  VALUES
    (p_github_username, p_assignment_id, p_assignment_title, p_section, p_repo_name, p_repo_url, p_evaluation_id, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET assignment_title = EXCLUDED.assignment_title,
      section          = EXCLUDED.section,
      repo_name        = EXCLUDED.repo_name,
      repo_url         = EXCLUDED.repo_url,
      evaluation_id    = COALESCE(EXCLUDED.evaluation_id, public.assignment_acceptances.evaluation_id),
      accepted_at      = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_acceptance(TEXT,BIGINT,TEXT,TEXT,TEXT,TEXT,BIGINT)
  TO anon, authenticated;

SELECT 'assignment_acceptances' AS tabla, COUNT(*) FROM public.assignment_acceptances;


-- ===== csharp/migration-multi-evaluation.sql =====

-- ============================================================
--  Migracion: Multi-evaluacion (Curso > Seccion > Evaluacion)
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Crea las tablas courses, sections, evaluations y agrega
--  section_id (nullable, forward-compatible) a 6 tablas
--  existentes. Un trigger sincroniza section_id desde section
--  TEXT para que los clientes v2.5.x sigan funcionando sin
--  cambios. Incluye backfill desde Config.Sections y
--  Config.EvaluationTypes.
-- ============================================================

-- ============================================================
--  1. TABLAS NUEVAS
-- ============================================================

CREATE TABLE IF NOT EXISTS public.courses (
  id BIGSERIAL PRIMARY KEY,
  code TEXT NOT NULL UNIQUE,
  name TEXT NOT NULL,
  active BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.sections (
  id BIGSERIAL PRIMARY KEY,
  course_id BIGINT NOT NULL REFERENCES public.courses(id) ON DELETE CASCADE,
  code TEXT NOT NULL,
  name TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(course_id, code)
);

CREATE TABLE IF NOT EXISTS public.evaluations (
  id BIGSERIAL PRIMARY KEY,
  section_id BIGINT NOT NULL REFERENCES public.sections(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  classroom_url TEXT,
  org TEXT,
  active BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(section_id, title)
);

CREATE INDEX IF NOT EXISTS idx_sections_course
  ON public.sections (course_id);
CREATE INDEX IF NOT EXISTS idx_evaluations_section
  ON public.evaluations (section_id);
CREATE INDEX IF NOT EXISTS idx_evaluations_active
  ON public.evaluations (active);

-- ============================================================
--  2. ROW LEVEL SECURITY
-- ============================================================

ALTER TABLE public.courses ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.sections ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.evaluations ENABLE ROW LEVEL SECURITY;

-- courses: anon lee (alumno fetchea al elegir), authenticated CRUD
DROP POLICY IF EXISTS "anon_read_courses" ON public.courses;
CREATE POLICY "anon_read_courses" ON public.courses
  FOR SELECT USING (true);
DROP POLICY IF EXISTS "auth_all_courses" ON public.courses;
CREATE POLICY "auth_all_courses" ON public.courses
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- sections: anon lee, authenticated CRUD
DROP POLICY IF EXISTS "anon_read_sections" ON public.sections;
CREATE POLICY "anon_read_sections" ON public.sections
  FOR SELECT USING (true);
DROP POLICY IF EXISTS "auth_all_sections" ON public.sections;
CREATE POLICY "auth_all_sections" ON public.sections
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- evaluations: anon lee solo activas, authenticated CRUD
DROP POLICY IF EXISTS "anon_read_evaluations" ON public.evaluations;
CREATE POLICY "anon_read_evaluations" ON public.evaluations
  FOR SELECT USING (active = true);
DROP POLICY IF EXISTS "auth_all_evaluations" ON public.evaluations;
CREATE POLICY "auth_all_evaluations" ON public.evaluations
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- ============================================================
--  3. ALTER assignments + 6 tablas con section_id
-- ============================================================

ALTER TABLE public.assignments
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

ALTER TABLE public.assignment_acceptances
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

ALTER TABLE public.assignment_acceptances
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

ALTER TABLE public.student_activity
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

ALTER TABLE public.online_clients
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

ALTER TABLE public.process_alerts
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

ALTER TABLE public.browser_history
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

ALTER TABLE public.suspicious_processes
  ADD COLUMN IF NOT EXISTS section_id BIGINT NULL
  REFERENCES public.sections(id) ON DELETE SET NULL;

-- ============================================================
--  4. FUNCTION sync_section_id + triggers
--  Sincroniza section_id desde section TEXT para coexistencia
--  forward-compatible con clientes v2.5.x que reportan via
--  section TEXT. En INSERT completa section_id si es NULL;
--  en UPDATE recalcula si section TEXT cambio; si section es
--  NULL, limpia section_id stale.
--
--  ASSUMPTION: section codes (section TEXT) son globalmente
--  unicos a traves de todos los cursos. Esto es valido para
--  el sistema legacy (Config.Sections = 001D/002D/003D). Si
--  en el futuro dos cursos comparten un mismo section code,
--  este trigger elegira arbitrariamente el primero que matchee
--  (LIMIT 1) y debera refinarse con contexto de curso.
-- ============================================================

CREATE OR REPLACE FUNCTION public.sync_section_id()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.section IS NULL THEN
    NEW.section_id := NULL;
  ELSIF (TG_OP = 'INSERT' AND NEW.section_id IS NULL)
     OR (TG_OP = 'UPDATE' AND NEW.section IS DISTINCT FROM OLD.section) THEN
    SELECT s.id INTO NEW.section_id
    FROM public.sections s
    WHERE s.code = NEW.section
    LIMIT 1;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_section_acceptances
  ON public.assignment_acceptances;
CREATE TRIGGER trg_sync_section_acceptances
  BEFORE INSERT OR UPDATE ON public.assignment_acceptances
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

DROP TRIGGER IF EXISTS trg_sync_section_activity
  ON public.student_activity;
CREATE TRIGGER trg_sync_section_activity
  BEFORE INSERT OR UPDATE ON public.student_activity
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

DROP TRIGGER IF EXISTS trg_sync_section_online
  ON public.online_clients;
CREATE TRIGGER trg_sync_section_online
  BEFORE INSERT OR UPDATE ON public.online_clients
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

DROP TRIGGER IF EXISTS trg_sync_section_alerts
  ON public.process_alerts;
CREATE TRIGGER trg_sync_section_alerts
  BEFORE INSERT OR UPDATE ON public.process_alerts
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

DROP TRIGGER IF EXISTS trg_sync_section_browser
  ON public.browser_history;
CREATE TRIGGER trg_sync_section_browser
  BEFORE INSERT OR UPDATE ON public.browser_history
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

DROP TRIGGER IF EXISTS trg_sync_section_susproc
  ON public.suspicious_processes;
CREATE TRIGGER trg_sync_section_susproc
  BEFORE INSERT OR UPDATE ON public.suspicious_processes
  FOR EACH ROW EXECUTE FUNCTION public.sync_section_id();

-- ============================================================
--  5. BACKFILL idempotente
--  Crea curso default FPY1101 + 3 secciones + 5 evaluaciones
--  por seccion desde Config.Sections y Config.EvaluationTypes.
--  Re-corrible: ON CONFLICT DO NOTHING.
-- ============================================================

INSERT INTO public.courses (code, name, active) VALUES
  ('FPY1101', 'Fisica I', true)
ON CONFLICT (code) DO NOTHING;

-- Secciones bajo FPY1101
INSERT INTO public.sections (course_id, code, name)
SELECT c.id, s.code, s.name
FROM public.courses c
CROSS JOIN (VALUES
  ('001D', 'Seccion 001D'),
  ('002D', 'Seccion 002D'),
  ('003D', 'Seccion 003D')
) AS s(code, name)
WHERE c.code = 'FPY1101'
ON CONFLICT (course_id, code) DO NOTHING;

-- Evaluaciones por seccion (mirror de Config.EvaluationTypes).
-- Scopeado al curso default FPY1101 via course_id para evitar
-- poluir secciones de otros cursos que compartan code.
INSERT INTO public.evaluations (section_id, title, active)
SELECT s.id, e.title, false
FROM public.sections s
CROSS JOIN (VALUES
  ('Evaluacion-1'),
  ('Evaluacion-2'),
  ('Evaluacion-3'),
  ('Evaluacion-4'),
  ('Examen')
) AS e(title)
WHERE s.course_id = (SELECT id FROM public.courses WHERE code = 'FPY1101')
  AND s.code IN ('001D', '002D', '003D')
ON CONFLICT (section_id, title) DO NOTHING;

-- ============================================================
--  6. REALTIME
--  Publica courses, sections, evaluations para que el panel
--  las vea en vivo al crear/editar.
-- ============================================================

DO $$
DECLARE
  t text;
  tables text[] := array['courses', 'sections', 'evaluations'];
BEGIN
  FOREACH t IN ARRAY tables LOOP
    IF NOT EXISTS (
      SELECT 1 FROM pg_publication_tables
      WHERE pubname = 'supabase_realtime'
        AND schemaname = 'public'
        AND tablename = t
    ) THEN
      EXECUTE format('ALTER PUBLICATION supabase_realtime ADD TABLE public.%I', t);
      RAISE NOTICE 'Realtime habilitado para public.%', t;
    ELSE
      RAISE NOTICE 'public.% ya estaba en supabase_realtime (sin cambios)', t;
    END IF;
  END LOOP;
END $$;

-- ============================================================
--  7. VERIFICACION
-- ============================================================

SELECT 'courses' AS tabla, COUNT(*) AS filas FROM public.courses
UNION ALL
SELECT 'sections', COUNT(*) FROM public.sections
UNION ALL
SELECT 'evaluations', COUNT(*) FROM public.evaluations
UNION ALL
SELECT 'assignments_con_eval', COUNT(*) FROM public.assignments WHERE evaluation_id IS NOT NULL
UNION ALL
SELECT 'online_con_section_id', COUNT(*) FROM public.online_clients WHERE section_id IS NOT NULL;


-- ===== csharp/migration-submissions.sql =====

-- ============================================================
--  Migracion: assignment_submissions (entrega formal de repo)
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Diferencia con assignment_acceptances:
--    - acceptances = el alumno "acepto" la tarea en Classroom
--    - submissions = el alumno "entrego" su repo (URL manual o
--      auto-detectada desde Classroom) como entrega formal.
--  Ambas tablas coexisten; aceptar != entregar.
-- ============================================================

-- Columna opt-in en assignments: si true, el alumno puede pegar una
-- URL de repo manualmente (sin pasar por Classroom).
ALTER TABLE public.assignments
  ADD COLUMN IF NOT EXISTS allows_manual_submission BOOLEAN NOT NULL DEFAULT FALSE;

CREATE TABLE IF NOT EXISTS public.assignment_submissions (
  id BIGSERIAL PRIMARY KEY,
  assignment_id BIGINT NOT NULL,
  github_username TEXT NOT NULL,
  repo_url TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'submitted',
  submitted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(github_username, assignment_id)
);
CREATE INDEX IF NOT EXISTS idx_submissions_assignment
  ON public.assignment_submissions (assignment_id, submitted_at DESC);
CREATE INDEX IF NOT EXISTS idx_submissions_user
  ON public.assignment_submissions (github_username, submitted_at DESC);

ALTER TABLE public.assignment_submissions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "anon_insert_submissions" ON public.assignment_submissions;
CREATE POLICY "anon_insert_submissions" ON public.assignment_submissions
  FOR INSERT WITH CHECK (true);

DROP POLICY IF EXISTS "anon_read_submissions" ON public.assignment_submissions;
CREATE POLICY "anon_read_submissions" ON public.assignment_submissions
  FOR SELECT TO anon, authenticated USING (true);

DROP POLICY IF EXISTS "anon_update_submissions" ON public.assignment_submissions;
CREATE POLICY "anon_update_submissions" ON public.assignment_submissions
  FOR UPDATE USING (true) WITH CHECK (true);

-- RPC upsert (SECURITY DEFINER) para registrar/actualizar entrega.
DROP FUNCTION IF EXISTS public.record_submission(BIGINT, TEXT, TEXT, TEXT);

CREATE OR REPLACE FUNCTION public.record_submission(
  p_assignment_id BIGINT,
  p_github_username TEXT,
  p_repo_url TEXT,
  p_status TEXT DEFAULT 'submitted'
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.assignment_submissions
    (assignment_id, github_username, repo_url, status, submitted_at)
  VALUES
    (p_assignment_id, p_github_username, p_repo_url, p_status, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET repo_url      = EXCLUDED.repo_url,
      status        = EXCLUDED.status,
      submitted_at  = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_submission(BIGINT,TEXT,TEXT,TEXT)
  TO anon, authenticated;

SELECT 'assignment_submissions' AS tabla, COUNT(*) FROM public.assignment_submissions;


-- ===== admin-next/migration-realtime.sql =====

-- ============================================================================
-- Realtime para el Panel del Profesor (admin-next)
-- ----------------------------------------------------------------------------
-- EJECUTAR UNA VEZ en Supabase: Dashboard -> SQL Editor -> New query -> Run.
-- Habilita las publicaciones de Realtime sobre las tablas que el panel
-- monitorea en vivo. Es idempotente: re-ejecutarlo no produce errores aunque
-- una tabla ya esté en la publicación.
-- ============================================================================

do $$
declare
  t text;
  tables text[] := array[
    'control',
    'online_clients',
    'browser_history',
    'cheat_events',
    'process_alerts',
    'suspicious_processes',
    'courses',
    'sections',
    'evaluations'
  ];
begin
  foreach t in array tables loop
    if not exists (
      select 1
      from pg_publication_tables
      where pubname = 'supabase_realtime'
        and schemaname = 'public'
        and tablename = t
    ) then
      execute format('alter publication supabase_realtime add table public.%I', t);
      raise notice 'Realtime habilitado para public.%', t;
    else
      raise notice 'public.% ya estaba en supabase_realtime (sin cambios)', t;
    end if;
  end loop;
end $$;


-- ===== csharp/migration-allowed-urls.sql =====

-- ============================================================
--  Migracion: allowed_urls (allowlist del navegador embebido,
--  editable por seccion desde el panel).
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Espejo de suspicious_processes (blocklist), pero AL REVES: aqui se
--  define lo PERMITIDO. Modelo: section IS NULL = regla GLOBAL (heredada
--  por todas las secciones); section = 'X' = extra de la seccion X. La
--  lista efectiva de un alumno de la seccion X es (section IS NULL)
--  UNION (section = 'X').
--
--  kind discrimina los DOS tipos de regla que ya existian hardcodeados
--  en Config.cs:
--    'domain'    -> match por SUFIJO de host (IsDomainAllowed): la fila
--                   y sus subdominios. Ej: 'github.com' permite
--                   classroom.github.com. NO uses TLDs ni dominios
--                   genericos amplios (serian un escape).
--    'exact_url' -> match por PREFIJO de scheme://host/path (IsUrlAllowed):
--                   habilita una ruta puntual sin abrir el host entero.
--                   Ej: 'https://www.google.com/a/duocuc.cl/acs'.
--
--  SEGURIDAD: el cliente C# usa esta tabla como fuente de verdad pero
--  CAE a Config.AllowedBrowseDomains/AllowedExactUrls (hardcode) si el
--  fetch falla o vuelve vacio. El fallback es la lista MAS restrictiva
--  conocida: un fetch fallido NUNCA amplia lo permitido.
-- ============================================================

-- ============================================================
--  1. TABLA allowed_urls
-- ============================================================
CREATE TABLE IF NOT EXISTS public.allowed_urls (
  id BIGSERIAL PRIMARY KEY,
  pattern TEXT NOT NULL,
  kind TEXT NOT NULL DEFAULT 'domain' CHECK (kind IN ('domain', 'exact_url')),
  section TEXT,
  section_id BIGINT REFERENCES public.sections(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Unicidad por (pattern, kind, section) tratando NULL como '' para que
-- el seed y los inserts futuros sean idempotentes (ON CONFLICT).
CREATE UNIQUE INDEX IF NOT EXISTS ux_allowed_urls_pattern_kind_section
  ON public.allowed_urls (pattern, kind, COALESCE(section, ''));

-- Indice de apoyo para la query del cliente (filtra por seccion).
CREATE INDEX IF NOT EXISTS idx_allowed_urls_section
  ON public.allowed_urls (section);

-- ============================================================
--  2. ROW LEVEL SECURITY
--  anon + authenticated leen (el cliente C# lee con anon key);
--  solo authenticated escribe (CRUD del profe en el panel).
-- ============================================================
ALTER TABLE public.allowed_urls ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "anon_read_allowed_urls" ON public.allowed_urls;
CREATE POLICY "anon_read_allowed_urls" ON public.allowed_urls
  FOR SELECT TO anon, authenticated USING (true);

DROP POLICY IF EXISTS "auth_all_allowed_urls" ON public.allowed_urls;
CREATE POLICY "auth_all_allowed_urls" ON public.allowed_urls
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- ============================================================
--  3. SEED de las reglas globales (section = NULL)
--  Copiado de Config.AllowedBrowseDomains (kind='domain') y
--  Config.AllowedExactUrls (kind='exact_url'). Mantener sincronizado
--  con el fallback de Config.cs. Idempotente (ON CONFLICT).
-- ============================================================
INSERT INTO public.allowed_urls (pattern, kind, section)
SELECT pat, 'domain', NULL
FROM unnest(ARRAY[
  'github.com',
  'githubusercontent.com',
  'login.microsoftonline.com',
  'login.live.com',
  'login.microsoft.com',
  'msftauth.net',
  'aadcdn.msftauth.net',
  'accounts.google.com',
  'accounts.google.cl',
  'mail.google.com',
  'googleusercontent.com'
]) AS pat
ON CONFLICT (pattern, kind, COALESCE(section, '')) DO NOTHING;

INSERT INTO public.allowed_urls (pattern, kind, section)
SELECT pat, 'exact_url', NULL
FROM unnest(ARRAY[
  'https://www.google.com/a/duocuc.cl/acs'
]) AS pat
ON CONFLICT (pattern, kind, COALESCE(section, '')) DO NOTHING;

-- ============================================================
--  4. Realtime: agregar allowed_urls a la publicacion.
--  Guardado contra duplicate_object para que re-correr no falle.
-- ============================================================
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_publication_tables
    WHERE pubname = 'supabase_realtime'
      AND schemaname = 'public'
      AND tablename = 'allowed_urls'
  ) THEN
    EXECUTE 'ALTER PUBLICATION supabase_realtime ADD TABLE public.allowed_urls';
    RAISE NOTICE 'Realtime habilitado para public.allowed_urls';
  ELSE
    RAISE NOTICE 'public.allowed_urls ya estaba en supabase_realtime (sin cambios)';
  END IF;
EXCEPTION
  WHEN duplicate_object THEN
    RAISE NOTICE 'public.allowed_urls ya estaba en la publicacion (duplicate_object)';
END $$;

-- ============================================================
--  5. VERIFICACION
-- ============================================================
SELECT 'allowed_urls' AS tabla, COUNT(*) AS filas FROM public.allowed_urls
UNION ALL
SELECT 'globales dominio (section NULL)', COUNT(*) FROM public.allowed_urls WHERE section IS NULL AND kind = 'domain'
UNION ALL
SELECT 'globales url exacta (section NULL)', COUNT(*) FROM public.allowed_urls WHERE section IS NULL AND kind = 'exact_url';


-- ===== csharp/migration-evaluation-control.sql =====

-- ============================================================
--  Migracion: Control por evaluacion + atribucion por evento
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Capa aditiva ENCIMA de migration-multi-evaluation.sql
--  (que ya provee courses > sections > evaluations PER-SECTION,
--  el trigger sync_section_id y section_id nullable en 6 tablas).
--
--  ORDEN DE EJECUCION: correr DESPUES de setup-supabase.sql
--  (provee set_updated_at() y el control global id=1) y DESPUES
--  de migration-multi-evaluation.sql (provee la tabla
--  evaluations referenciada por todas las FK de aca).
--
--  Esta migracion agrega, de forma aditiva y forward-compatible:
--    1. evaluations.number + UNIQUE(section_id, number) (handle
--       numerico estable para la resolucion de control). El valor
--       de number lo asigna el panel admin; aca NO se adivina
--       desde el title.
--    2. evaluation_control: override POR EVALUACION sobre el
--       control GLOBAL id=1 (que sigue siendo el fallback).
--    3. evaluation_id nullable en las tablas de evento/identidad
--       que aun no lo tienen (incluido cheat_events, que hoy no
--       tiene ni section ni evaluation).
--
--  NO destructivo: no hace DROP de constraints, no swapea UNIQUE
--  keys (el swap de online_clients es de otra migracion), no
--  modifica RPCs (van aparte) y NO HACE NINGUN BACKFILL (ni de
--  number ni de atribucion de evaluation_id: ambos van aparte).
--  Los clientes legacy que leen el control global id=1 siguen
--  funcionando sin cambios.
-- ============================================================

-- ============================================================
--  1. evaluations: number + UNIQUE(section_id, number)
--  number es el handle numerico estable para joinear el
--  control y resolver la evaluacion desde el cliente. title
--  queda como display. Numeracion POR SECCION (cada seccion
--  numera sus evaluaciones de forma independiente).
-- ============================================================

ALTER TABLE public.evaluations
  ADD COLUMN IF NOT EXISTS number INT;

-- UNIQUE por (section_id, number). Indice unico parcial: solo
-- aplica cuando number NO es NULL, para no chocar con filas
-- legacy que aun no tienen number asignado. La columna nace
-- NULL para todas las filas existentes; el panel admin asigna
-- number explicitamente (nunca se infiere desde el title).
CREATE UNIQUE INDEX IF NOT EXISTS ux_eval_section_number
  ON public.evaluations (section_id, number)
  WHERE number IS NOT NULL;

-- ============================================================
--  2. evaluation_control: override por evaluacion
--  NULL en un campo = heredar del control GLOBAL id=1.
--  El control global (public.control id=1) NO se toca: sigue
--  siendo el fallback para clientes legacy y cuando no hay
--  override para la evaluacion.
-- ============================================================

CREATE TABLE IF NOT EXISTS public.evaluation_control (
  evaluation_id BIGINT PRIMARY KEY
    REFERENCES public.evaluations(id) ON DELETE CASCADE,
  internet_block BOOLEAN,
  force_lockdown BOOLEAN,
  message TEXT,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_by TEXT
);

-- evaluation_id es PK -> ya garantiza UNIQUE (un override por
-- evaluacion). No se agrega UNIQUE redundante.

-- updated_at automatico, reutilizando set_updated_at() de
-- setup-supabase.sql (CREATE OR REPLACE alla; aca solo el
-- trigger, idempotente via DROP IF EXISTS).
DROP TRIGGER IF EXISTS trg_eval_control_updated_at
  ON public.evaluation_control;
CREATE TRIGGER trg_eval_control_updated_at
  BEFORE UPDATE ON public.evaluation_control
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ============================================================
--  3. evaluation_id nullable en tablas de evento/identidad
--  Aditivo y nullable: sin backfill, sin FK NOT NULL. ON DELETE
--  SET NULL para no perder eventos historicos si se borra una
--  evaluacion. assignment_acceptances y assignments ya tienen
--  evaluation_id (migration-multi-evaluation.sql), pero se
--  re-aplican con IF NOT EXISTS por seguridad (no-op si existen).
-- ============================================================

ALTER TABLE public.process_alerts
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

ALTER TABLE public.browser_history
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

ALTER TABLE public.student_activity
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

-- online_clients gana evaluation_id para agrupar re-rendiciones
-- (correccion 4). El swap del UNIQUE key a COALESCE(evaluation_id,0)
-- es de OTRA migracion (resit-isolation); aca SOLO la columna.
ALTER TABLE public.online_clients
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

-- cheat_events hoy no tiene ni section ni evaluation. Se agrega
-- evaluation_id nullable para poder atribuir (best-effort, en
-- otra migracion) sin romper inserts anon existentes.
ALTER TABLE public.cheat_events
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

-- assignments ya tiene evaluation_id desde migration-multi-evaluation.sql;
-- se reafirma idempotente (no-op si ya existe).
ALTER TABLE public.assignments
  ADD COLUMN IF NOT EXISTS evaluation_id BIGINT NULL
  REFERENCES public.evaluations(id) ON DELETE SET NULL;

-- ============================================================
--  4. INDICES sobre las nuevas columnas evaluation_id
--  Soportan los filtros por evaluacion del panel y del resolver
--  por-evaluacion del cliente.
-- ============================================================

CREATE INDEX IF NOT EXISTS idx_process_alerts_eval
  ON public.process_alerts (evaluation_id);
CREATE INDEX IF NOT EXISTS idx_browser_history_eval
  ON public.browser_history (evaluation_id);
CREATE INDEX IF NOT EXISTS idx_student_activity_eval
  ON public.student_activity (evaluation_id);
CREATE INDEX IF NOT EXISTS idx_online_clients_eval
  ON public.online_clients (evaluation_id);
CREATE INDEX IF NOT EXISTS idx_cheat_events_eval
  ON public.cheat_events (evaluation_id);

-- ============================================================
--  5. ROW LEVEL SECURITY para evaluation_control
--  Mismo patron que control id=1: anon LEE (el cliente pollea
--  su override para resolver el lock), authenticated ALL (el
--  panel escribe). Las escrituras sensibles via RPC son de otra
--  migracion (no se agregan RPCs aca).
-- ============================================================

ALTER TABLE public.evaluation_control ENABLE ROW LEVEL SECURITY;

-- evaluation_control: anon lee (cliente pollea su override),
-- authenticated CRUD (panel).
DROP POLICY IF EXISTS "anon_read_evaluation_control"
  ON public.evaluation_control;
CREATE POLICY "anon_read_evaluation_control" ON public.evaluation_control
  FOR SELECT USING (true);
DROP POLICY IF EXISTS "auth_all_evaluation_control"
  ON public.evaluation_control;
CREATE POLICY "auth_all_evaluation_control" ON public.evaluation_control
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- ============================================================
--  6. REALTIME
--  Publica evaluation_control para que el cliente reciba en vivo
--  los cambios de override (lock/unlock por evaluacion).
-- ============================================================

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_publication_tables
    WHERE pubname = 'supabase_realtime'
      AND schemaname = 'public'
      AND tablename = 'evaluation_control'
  ) THEN
    EXECUTE 'ALTER PUBLICATION supabase_realtime ADD TABLE public.evaluation_control';
    RAISE NOTICE 'Realtime habilitado para public.evaluation_control';
  ELSE
    RAISE NOTICE 'public.evaluation_control ya estaba en supabase_realtime (sin cambios)';
  END IF;
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- ============================================================
--  7. VERIFICACION
-- ============================================================

SELECT 'evaluations_con_number' AS tabla, COUNT(*) AS filas
  FROM public.evaluations WHERE number IS NOT NULL
UNION ALL
SELECT 'evaluation_control', COUNT(*) FROM public.evaluation_control
UNION ALL
SELECT 'process_alerts_con_eval', COUNT(*)
  FROM public.process_alerts WHERE evaluation_id IS NOT NULL
UNION ALL
SELECT 'browser_history_con_eval', COUNT(*)
  FROM public.browser_history WHERE evaluation_id IS NOT NULL
UNION ALL
SELECT 'student_activity_con_eval', COUNT(*)
  FROM public.student_activity WHERE evaluation_id IS NOT NULL
UNION ALL
SELECT 'online_clients_con_eval', COUNT(*)
  FROM public.online_clients WHERE evaluation_id IS NOT NULL
UNION ALL
SELECT 'cheat_events_con_eval', COUNT(*)
  FROM public.cheat_events WHERE evaluation_id IS NOT NULL;


-- ===== csharp/migration-version-visibility.sql =====

-- ============================================================
--  Migracion: visibilidad de version
--  - online_clients.app_version : version que corre cada alumno (la
--    reporta el cliente en el heartbeat -> el panel la muestra por PC).
--  - control.update_requested_at : el profe lo setea = NOW() desde el
--    panel para pedir a los clientes que actualicen (update MANUAL,
--    disparado; el cliente NO hace fetch automatico a GitHub).
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- 1. Columnas nuevas ----------------------------------------------------
ALTER TABLE public.online_clients
  ADD COLUMN IF NOT EXISTS app_version TEXT;

ALTER TABLE public.control
  ADD COLUMN IF NOT EXISTS update_requested_at TIMESTAMPTZ;

-- 2. heartbeat RPC: sumar p_app_version --------------------------------
-- p_app_version es nullable (DEFAULT NULL) para que clientes viejos que
-- llaman con la firma de 8 args sigan resolviendo. DROP previo de la firma
-- vieja (8 params) antes del CREATE: con una firma distinta CREATE OR
-- REPLACE crearia un NUEVO signature en vez de reemplazar, dejando dos
-- funciones vivas y rompiendo a PostgREST (300 ambiguous). UNA firma por
-- nombre. El UPDATE usa COALESCE para no pisar la version con NULL cuando
-- un cliente viejo (que no la manda) hace heartbeat.
DROP FUNCTION IF EXISTS public.heartbeat(
  TEXT, TEXT, TEXT, TEXT, JSONB, TEXT, TEXT, BIGINT);

CREATE OR REPLACE FUNCTION public.heartbeat(
  p_pc_name TEXT,
  p_github_username TEXT,
  p_github_email TEXT DEFAULT NULL,
  p_section TEXT DEFAULT NULL,
  p_processes JSONB DEFAULT '[]'::jsonb,
  p_internet_state TEXT DEFAULT 'free',
  p_lockdown_state TEXT DEFAULT 'none',
  p_evaluation_id BIGINT DEFAULT NULL,
  p_app_version TEXT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  INSERT INTO public.online_clients
    (pc_name, github_username, github_email, section, processes,
     internet_state, lockdown_state, evaluation_id, app_version, last_seen)
  VALUES
    (p_pc_name, p_github_username, p_github_email, p_section, p_processes,
     p_internet_state, p_lockdown_state, p_evaluation_id, p_app_version, NOW())
  ON CONFLICT (pc_name, github_username) DO UPDATE
  SET github_email   = EXCLUDED.github_email,
      section        = EXCLUDED.section,
      processes      = EXCLUDED.processes,
      internet_state = EXCLUDED.internet_state,
      lockdown_state = EXCLUDED.lockdown_state,
      evaluation_id  = COALESCE(EXCLUDED.evaluation_id, public.online_clients.evaluation_id),
      app_version    = COALESCE(EXCLUDED.app_version, public.online_clients.app_version),
      last_seen      = NOW();
END;
$$;

GRANT EXECUTE ON FUNCTION public.heartbeat(TEXT,TEXT,TEXT,TEXT,JSONB,TEXT,TEXT,BIGINT,TEXT)
  TO anon, authenticated;

-- 3. Verificacion -------------------------------------------------------
SELECT 'online_clients.app_version' AS check, COUNT(*) AS filas_con_version
FROM public.online_clients WHERE app_version IS NOT NULL
UNION ALL
SELECT 'control.update_requested_at', COUNT(*)
FROM public.control WHERE update_requested_at IS NOT NULL;


-- ===== csharp/migration-self-lock.sql =====

-- ============================================================
--  Migracion: auto-lock por trampa local visible + liberable remoto
--
--  Hoy la "pantalla roja" por trampa LOCAL (repo sucio, navegacion
--  prohibida, copilot) NO es visible en el panel ni liberable remoto:
--  solo la clave del profe en la maquina la cierra. Esta migracion deja
--  que el cliente (anon) REPORTE su propio bloqueo en targeted_lockdowns
--  via una RPC SECURITY DEFINER, para que el profe lo VEA y lo
--  DESBLOQUEE desde el panel (la liberacion sigue siendo authenticated:
--  el alumno NO puede auto-liberarse).
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- 1. Distinguir origen del lock: 'teacher' (dirigido por el profe) vs
--    'trap' (auto-reportado por una trampa local del cliente).
ALTER TABLE public.targeted_lockdowns
  ADD COLUMN IF NOT EXISTS source TEXT NOT NULL DEFAULT 'teacher'
  CHECK (source IN ('teacher', 'trap'));

-- 2. RPC para que el cliente reporte su propio bloqueo (anon-callable).
--    SECURITY DEFINER: escribe aunque el cliente sea anon (la RLS solo deja
--    escribir a authenticated). Reportarse bloqueado NO es explotable; la
--    LIBERACION queda fuera de esta RPC (solo el profe authenticated apaga
--    active desde el panel). UNA firma por nombre (DROP previo).
DROP FUNCTION IF EXISTS public.report_self_lock(TEXT, TEXT, TEXT, TEXT, TEXT);

CREATE OR REPLACE FUNCTION public.report_self_lock(
  p_pc_name TEXT,
  p_github_username TEXT,
  p_section TEXT DEFAULT NULL,
  p_reason TEXT DEFAULT NULL,
  p_source TEXT DEFAULT 'trap'
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  INSERT INTO public.targeted_lockdowns
    (pc_name, github_username, active, reason, source, created_at, released_at)
  VALUES
    (p_pc_name, p_github_username, true, p_reason,
     COALESCE(p_source, 'trap'), NOW(), NULL)
  ON CONFLICT (pc_name, github_username) DO UPDATE
  SET active      = true,
      reason      = EXCLUDED.reason,
      source      = EXCLUDED.source,
      created_at  = NOW(),
      released_at = NULL;
END;
$$;

GRANT EXECUTE ON FUNCTION public.report_self_lock(TEXT, TEXT, TEXT, TEXT, TEXT)
  TO anon, authenticated;

-- 3. Verificacion
SELECT 'targeted_lockdowns activos' AS check, COUNT(*) AS n
FROM public.targeted_lockdowns WHERE active
UNION ALL
SELECT 'por trampa (source=trap)', COUNT(*)
FROM public.targeted_lockdowns WHERE active AND source = 'trap';


-- ===== csharp/migration-enrollments.sql =====

-- ============================================================
--  Migracion: enrollments (roster importado desde Blackboard)
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Capa aditiva ENCIMA de migration-multi-evaluation.sql
--  (que ya provee courses > sections > evaluations PER-SECTION).
--  La FK section_id apunta a public.sections(id).
--
--  ORDEN DE EJECUCION: correr DESPUES de setup-supabase.sql
--  (provee set_updated_at()) y DESPUES de migration-multi-evaluation.sql
--  (provee la tabla sections referenciada por la FK de aca).
--
--  enrollments es la PRIMERA tabla con PII (full_name, email). Por eso
--  su politica de RLS es authenticated-ONLY: NO hay policy anon SELECT.
--  El unico acceso anon es via la RPC get_my_enrollment, que devuelve
--  SOLO campos de confirmacion no-PII (nunca full_name ni email ni
--  blackboard_student_id). El panel docente (authenticated) importa el
--  roster y asigna github manualmente.
--
--  NO destructivo: no hace DROP de tablas/constraints existentes, no
--  toca otras tablas. github_username nace NULL (el docente lo completa
--  en el panel; bb-dl exporta el roster con github en null).
-- ============================================================

-- ============================================================
--  1. TABLA enrollments
--  status NUNCA se degrada en un import (ver RPC import_enrollment):
--  un re-import no puede revivir un estado mas bajo. created_at /
--  updated_at automaticos (updated_at via trigger set_updated_at()).
-- ============================================================

CREATE TABLE IF NOT EXISTS public.enrollments (
  id BIGSERIAL PRIMARY KEY,
  section_id BIGINT NOT NULL
    REFERENCES public.sections(id) ON DELETE CASCADE,
  full_name TEXT NOT NULL,
  email TEXT,
  github_username TEXT,
  blackboard_student_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'enrolled',
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  -- Clave de conflicto del import: un alumno (por blackboard id) aparece
  -- una sola vez por seccion. Re-import = UPDATE, no fila duplicada.
  UNIQUE(section_id, blackboard_student_id)
);

-- ============================================================
--  2. INDICES
--  - ux_enroll_section_github: UNIQUE parcial sobre lower(github)
--    POR SECCION, solo cuando github NO es NULL (multiples filas con
--    github NULL conviven; dos alumnos de la misma seccion no pueden
--    reclamar el mismo github). El set_enrollment_github deja que el
--    23505 de este indice aflore al caller.
--  - idx_enroll_section_github_lower: acelera el lookup por github
--    (get_my_enrollment hace lower(github_username) = lower(...)).
--  - idx_enroll_section: filtros del panel por seccion.
-- ============================================================

CREATE UNIQUE INDEX IF NOT EXISTS ux_enroll_section_github
  ON public.enrollments (section_id, lower(github_username))
  WHERE github_username IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_enroll_section_github_lower
  ON public.enrollments (lower(github_username));

CREATE INDEX IF NOT EXISTS idx_enroll_section
  ON public.enrollments (section_id);

-- updated_at automatico, reutilizando set_updated_at() de
-- setup-supabase.sql (CREATE OR REPLACE alla; aca solo el trigger,
-- idempotente via DROP IF EXISTS).
DROP TRIGGER IF EXISTS trg_enrollments_updated_at
  ON public.enrollments;
CREATE TRIGGER trg_enrollments_updated_at
  BEFORE UPDATE ON public.enrollments
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ============================================================
--  3. ROW LEVEL SECURITY (authenticated-ONLY)
--  enrollments es la primera tabla con PII. A DIFERENCIA del resto
--  de las tablas (que tienen policy anon SELECT/INSERT), aca NO hay
--  ninguna policy para anon: el cliente anon NO puede leer ni escribir
--  enrollments directamente. Solo authenticated (panel docente) tiene
--  acceso completo. El cliente anon confirma su inscripcion unicamente
--  via la RPC get_my_enrollment (SECURITY DEFINER, no-PII).
-- ============================================================

ALTER TABLE public.enrollments ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "auth_all_enrollments" ON public.enrollments;
CREATE POLICY "auth_all_enrollments" ON public.enrollments
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- (Intencionalmente SIN policy para anon: RLS deniega cualquier
--  SELECT/INSERT/UPDATE/DELETE anon sobre enrollments.)

-- ============================================================
--  4. RPCs
--  Disciplina (igual que record_acceptance / heartbeat):
--    - SECURITY DEFINER + SET search_path = public
--    - exactamente UNA firma por nombre (sin overload -> sin 300 de
--      PostgREST). Params nuevos con DEFAULT NULL.
--    - DROP de la firma previa antes del CREATE (CREATE OR REPLACE con
--      firma distinta crearia un segundo signature).
--    - re-GRANT EXECUTE sobre la firma COMPLETA.
-- ============================================================

-- ------------------------------------------------------------
--  4a. import_enrollment (authenticated: panel docente)
--  Upsert por (section_id, blackboard_student_id). El import NUNCA
--  degrada status: si la fila ya existe con un status, se conserva el
--  existente (COALESCE del entrante NO pisa el de la fila). github del
--  entrante solo se aplica si llega no-NULL (el import de bb-dl manda
--  github NULL; el docente lo asigna aparte con set_enrollment_github).
-- ------------------------------------------------------------
DROP FUNCTION IF EXISTS public.import_enrollment(
  BIGINT, TEXT, TEXT, TEXT, TEXT);

CREATE OR REPLACE FUNCTION public.import_enrollment(
  p_section_id BIGINT,
  p_full_name TEXT,
  p_email TEXT,
  p_blackboard_student_id TEXT,
  p_github_username TEXT DEFAULT NULL
) RETURNS BIGINT
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO public.enrollments
    (section_id, full_name, email, github_username, blackboard_student_id)
  VALUES
    (p_section_id, p_full_name, p_email, p_github_username, p_blackboard_student_id)
  ON CONFLICT (section_id, blackboard_student_id) DO UPDATE
  SET full_name       = EXCLUDED.full_name,
      email           = EXCLUDED.email,
      -- github solo se actualiza si el import trae uno no-NULL; nunca
      -- borra un github ya asignado por el docente.
      github_username = COALESCE(EXCLUDED.github_username, public.enrollments.github_username)
      -- status NO se incluye: el import preserva el status existente
      -- (no lo degrada ni lo cambia). Filas nuevas usan el DEFAULT
      -- 'enrolled'.
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;
GRANT EXECUTE ON FUNCTION public.import_enrollment(BIGINT,TEXT,TEXT,TEXT,TEXT)
  TO authenticated;

-- ------------------------------------------------------------
--  4b. set_enrollment_github (authenticated: panel docente)
--  Asigna/cambia el github de una inscripcion. El UNIQUE parcial
--  ux_enroll_section_github puede lanzar 23505 (github duplicado en la
--  seccion): NO se captura; se deja aflorar al caller para que el panel
--  muestre el conflicto. Pasar NULL limpia el github.
-- ------------------------------------------------------------
DROP FUNCTION IF EXISTS public.set_enrollment_github(
  BIGINT, TEXT);

CREATE OR REPLACE FUNCTION public.set_enrollment_github(
  p_enrollment_id BIGINT,
  p_github_username TEXT
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  UPDATE public.enrollments
  SET github_username = p_github_username
  WHERE id = p_enrollment_id;
END;
$$;
GRANT EXECUTE ON FUNCTION public.set_enrollment_github(BIGINT,TEXT)
  TO authenticated;

-- ------------------------------------------------------------
--  4c. get_my_enrollment (anon + authenticated: cliente C#)
--  El UNICO acceso del cliente anon a enrollments. SECURITY DEFINER
--  para saltar la RLS authenticated-only, PERO devuelve SOLO campos de
--  confirmacion NO-PII: section_id, status y un boolean found. NUNCA
--  devuelve full_name, email ni blackboard_student_id (no debe poder
--  usarse como oraculo de PII). Match por (section_id, lower(github)).
-- ------------------------------------------------------------
DROP FUNCTION IF EXISTS public.get_my_enrollment(
  TEXT, BIGINT);

CREATE OR REPLACE FUNCTION public.get_my_enrollment(
  p_github_username TEXT,
  p_section_id BIGINT
) RETURNS TABLE (
  section_id BIGINT,
  status TEXT,
  found BOOLEAN
)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY
  SELECT e.section_id, e.status, TRUE AS found
  FROM public.enrollments e
  WHERE e.section_id = p_section_id
    AND e.github_username IS NOT NULL
    AND lower(e.github_username) = lower(p_github_username)
  LIMIT 1;

  -- Si no hubo match, devolver una fila de confirmacion negativa sin
  -- exponer PII (found = false). Mantiene la forma de respuesta estable
  -- para el cliente.
  IF NOT FOUND THEN
    RETURN QUERY SELECT p_section_id, NULL::TEXT, FALSE;
  END IF;
END;
$$;
GRANT EXECUTE ON FUNCTION public.get_my_enrollment(TEXT,BIGINT)
  TO anon, authenticated;

-- ============================================================
--  5. VERIFICACION
--  (enrollments NO se publica en realtime: no hay consumidor en vivo.)
-- ============================================================

SELECT 'enrollments' AS tabla, COUNT(*) AS filas FROM public.enrollments
UNION ALL
SELECT 'enrollments_con_github', COUNT(*)
  FROM public.enrollments WHERE github_username IS NOT NULL;


-- ===== csharp/migration-enrollments-view.sql =====

-- ============================================================
--  Migracion: v_enrollment_status (vista de cruce roster vs actividad)
--  Idempotente. Correr en Supabase SQL Editor.
--
--  Capa de SOLO LECTURA encima de:
--    - enrollments               (roster importado; migration-enrollments.sql)
--    - assignment_acceptances    (acepto la tarea; migration-acceptances.sql)
--    - assignment_submissions    (entrego el repo; migration-submissions.sql)
--    - sections                  (resolucion de seccion; migration-multi-evaluation.sql)
--
--  ORDEN DE EJECUCION: correr DESPUES de migration-enrollments.sql,
--  migration-acceptances.sql, migration-submissions.sql y
--  migration-multi-evaluation.sql (todas proveen los objetos que la
--  vista referencia).
--
--  Proposito: dar al panel docente una unica fuente de verdad para
--  validar el roster contra la actividad real, SIN joins cross-table del
--  lado cliente. La vista cruza por github (case-insensitive) y emite,
--  por fila, si el github fue resuelto, si acepto y si entrego.
--
--  Diseno del cruce (github-first):
--    - Lado ROSTER: cada inscripcion 'enrolled' es una fila. Si tiene
--      github, se busca su actividad (acceptances/submissions) por
--      lower(github). Las inscripciones sin github son la cola de
--      "falta asignar github".
--    - Lado ORPHAN: cada github visto en la actividad que NO matchea
--      ninguna inscripcion de SU seccion es un huerfano (github fantasma:
--      actividad sin roster que la respalde).
--
--  Resolucion de seccion (COALESCE) para el lado ORPHAN: la actividad
--  legacy puede traer section_id NULL (cliente viejo que solo manda
--  section TEXT antes de que el trigger sync_section_id lo complete, o
--  un code que no matchea ninguna seccion). Se resuelve
--  COALESCE(a.section_id, s_by_code.id). Si AUN asi queda NULL, la fila
--  NO es huerfana: va al bucket separado 'seccion sin resolver'
--  (source = 'unresolved_section'), porque sin seccion no se la puede
--  contrastar contra ningun roster.
--
--  NO destructivo: solo CREATE OR REPLACE VIEW + GRANT SELECT. No toca
--  tablas ni datos. Re-corrible.
-- ============================================================

-- ============================================================
--  v_enrollment_status
--  Columnas (estables; el panel mapea EnrollmentStatusRow):
--    source            'roster' | 'orphan' | 'unresolved_section'
--    enrollment_id     id de enrollments (NULL en orphan/unresolved)
--    section_id        seccion resuelta (NULL solo en 'unresolved_section')
--    full_name         PII; NULL en orphan/unresolved (no hay roster)
--    email             PII; NULL en orphan/unresolved
--    github_username   github de la inscripcion o de la actividad huerfana
--    status            status de la inscripcion (NULL fuera de 'roster')
--    github_resolved   TRUE si la fila tiene un github no-NULL
--    accepted          TRUE si ese github acepto al menos una tarea
--    submitted         TRUE si ese github entrego al menos un repo
--
--  Es una vista RLS-aware: corre con los privilegios del caller. El
--  panel docente (authenticated) puede leer enrollments; por eso la
--  vista expone PII (full_name/email) SOLO para el rol authenticated.
--  El rol anon NO recibe GRANT (ver seccion de GRANT abajo).
-- ============================================================

CREATE OR REPLACE VIEW public.v_enrollment_status AS
WITH
-- Un github distinto por seccion presente en la actividad, con la
-- seccion resuelta via COALESCE(section_id, lookup por code). Sirve
-- tanto para detectar huerfanos como para clasificar 'seccion sin
-- resolver'. lower(github) es la clave de cruce.
activity_github AS (
  SELECT
    lower(a.github_username) AS github_lower,
    a.github_username        AS github_username,
    COALESCE(a.section_id, s_by_code.id) AS section_id,
    bool_or(TRUE)            AS accepted,
    bool_or(sub.id IS NOT NULL) AS submitted
  FROM public.assignment_acceptances a
  LEFT JOIN public.sections s_by_code
    ON a.section_id IS NULL
   AND a.section IS NOT NULL
   AND s_by_code.code = a.section
  LEFT JOIN public.assignment_submissions sub
    ON lower(sub.github_username) = lower(a.github_username)
  WHERE a.github_username IS NOT NULL
  GROUP BY
    lower(a.github_username),
    a.github_username,
    COALESCE(a.section_id, s_by_code.id)
),
-- Igual que arriba pero desde submissions, para capturar github que
-- entrego sin tener una fila de acceptance (entrega manual directa,
-- flujo allows_manual_submission). submissions NO tiene columna de
-- seccion propia, asi que la seccion se resuelve en cascada:
--   1) de la acceptance del mismo github, si existe (ag.section_id);
--   2) si no, del ROSTER por lower(github) (e_by_gh.section_id) — el
--      alumno inscripto que entrego manualmente sin aceptar debe contar
--      como entregado en SU seccion, no caer en 'seccion sin resolver'.
-- El fallback de roster se aplica SOLO si hay exactamente UN enrollment
-- 'enrolled' que matchee el github (sub-select con LIMIT y guardado por
-- un conteo): si el github aparece inscripto en mas de una seccion, se
-- deja NULL (colision multi-seccion = genuinamente sin resolver). Si no
-- hay acceptance NI match en el roster, queda NULL -> 'seccion sin
-- resolver' (correcto: actividad sin seccion ni inscripcion).
submission_github AS (
  SELECT
    lower(sub.github_username) AS github_lower,
    sub.github_username        AS github_username,
    COALESCE(ag.section_id, roster_sec.section_id) AS section_id,
    COALESCE(ag.accepted, FALSE) AS accepted,
    TRUE                       AS submitted
  FROM public.assignment_submissions sub
  LEFT JOIN activity_github ag
    ON ag.github_lower = lower(sub.github_username)
  -- Fallback al roster: section_id del unico enrollment que matchee el
  -- github. Si matchea 0 o >1, devuelve NULL (no resuelve la seccion).
  LEFT JOIN LATERAL (
    SELECT CASE WHEN COUNT(*) = 1 THEN MIN(e.section_id) END AS section_id
    FROM public.enrollments e
    WHERE e.status = 'enrolled'
      AND e.github_username IS NOT NULL
      AND lower(e.github_username) = lower(sub.github_username)
  ) roster_sec ON TRUE
  WHERE sub.github_username IS NOT NULL
),
-- Union de actividad por (github_lower, section_id). Colapsa acceptance
-- y submission del mismo github/seccion en una sola fila de actividad.
activity AS (
  SELECT
    github_lower,
    max(github_username) AS github_username,
    section_id,
    bool_or(accepted)  AS accepted,
    bool_or(submitted) AS submitted
  FROM (
    SELECT github_lower, github_username, section_id, accepted, submitted FROM activity_github
    UNION ALL
    SELECT github_lower, github_username, section_id, accepted, submitted FROM submission_github
  ) u
  GROUP BY github_lower, section_id
)

-- ----------------------------------------------------------------
-- Lado ROSTER: una fila por inscripcion 'enrolled'. accepted/submitted
-- se cruzan por (lower(github), section_id) contra la actividad. Las
-- inscripciones sin github tienen github_resolved=FALSE y accepted/
-- submitted en FALSE (no hay con que cruzar): son la cola de "falta
-- asignar github".
-- ----------------------------------------------------------------
SELECT
  'roster'::text                       AS source,
  e.id                                 AS enrollment_id,
  e.section_id                         AS section_id,
  e.full_name                          AS full_name,
  e.email                              AS email,
  e.github_username                    AS github_username,
  e.status                             AS status,
  (e.github_username IS NOT NULL)      AS github_resolved,
  COALESCE(act.accepted, FALSE)        AS accepted,
  COALESCE(act.submitted, FALSE)       AS submitted
FROM public.enrollments e
LEFT JOIN activity act
  ON e.github_username IS NOT NULL
 AND act.github_lower = lower(e.github_username)
 AND act.section_id  IS NOT DISTINCT FROM e.section_id
WHERE e.status = 'enrolled'

UNION ALL

-- ----------------------------------------------------------------
-- Lado ORPHAN: github con actividad en una seccion RESUELTA que NO
-- matchea ninguna inscripcion 'enrolled' de esa misma seccion. Es un
-- github fantasma (actividad sin roster). source='orphan'.
-- ----------------------------------------------------------------
SELECT
  'orphan'::text          AS source,
  NULL::bigint            AS enrollment_id,
  act.section_id          AS section_id,
  NULL::text              AS full_name,
  NULL::text              AS email,
  act.github_username     AS github_username,
  NULL::text              AS status,
  TRUE                    AS github_resolved,
  act.accepted            AS accepted,
  act.submitted           AS submitted
FROM activity act
WHERE act.section_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM public.enrollments e
    WHERE e.status = 'enrolled'
      AND e.github_username IS NOT NULL
      AND lower(e.github_username) = act.github_lower
      AND e.section_id = act.section_id
  )

UNION ALL

-- ----------------------------------------------------------------
-- Bucket SEPARADO 'seccion sin resolver': actividad cuya seccion no se
-- pudo resolver (section_id NULL tras el COALESCE). NO es huerfana: sin
-- seccion no se la puede contrastar contra ningun roster. Se mantiene
-- aparte para que el panel no la mezcle con los huerfanos reales.
-- ----------------------------------------------------------------
SELECT
  'unresolved_section'::text AS source,
  NULL::bigint               AS enrollment_id,
  NULL::bigint               AS section_id,
  NULL::text                 AS full_name,
  NULL::text                 AS email,
  act.github_username        AS github_username,
  NULL::text                 AS status,
  TRUE                       AS github_resolved,
  act.accepted               AS accepted,
  act.submitted              AS submitted
FROM activity act
WHERE act.section_id IS NULL;

-- ============================================================
--  GRANT
--  La vista expone PII (full_name/email del lado roster). Solo el rol
--  authenticated (panel docente) recibe SELECT. anon NO: mantiene la
--  garantia de enrollments (primera tabla PII, authenticated-only). La
--  vista NO es SECURITY DEFINER: respeta la RLS del caller, asi que
--  aunque alguien forzara el GRANT a anon, la RLS de enrollments igual
--  bloquearia el lado roster.
-- ============================================================

REVOKE ALL ON public.v_enrollment_status FROM anon;
GRANT SELECT ON public.v_enrollment_status TO authenticated;

-- ============================================================
--  VERIFICACION
-- ============================================================

SELECT source, COUNT(*) AS filas
FROM public.v_enrollment_status
GROUP BY source
ORDER BY source;


-- ===== csharp/migration-exam-mode.sql =====

-- ============================================================
--  Migracion: modo de evaluacion por evaluacion
--  - evaluations.exam_mode  : politica de bloqueo de la evaluacion.
--    Off       = sin aplicacion del modo examen.
--    AuditOnly = solo registra/observa, no bloquea.
--    SoftLock  = bloqueo suave (avisos, sin forzar).
--    HardLock  = bloqueo duro (forzado).
--    Default 'Off' para no cambiar el comportamiento de filas existentes.
--  - evaluations.policy_json : configuracion adicional del modo (JSONB),
--    nullable; las filas heredan NULL hasta que el profe la define.
--  No toca RLS: evaluations ya tiene policies.
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- 1. Columnas nuevas ----------------------------------------------------
ALTER TABLE public.evaluations
  ADD COLUMN IF NOT EXISTS exam_mode TEXT NOT NULL DEFAULT 'Off'
  CHECK (exam_mode IN ('Off','AuditOnly','SoftLock','HardLock'));

ALTER TABLE public.evaluations
  ADD COLUMN IF NOT EXISTS policy_json JSONB;

-- 2. Verificacion -------------------------------------------------------
SELECT 'evaluations.exam_mode' AS check, COUNT(*) AS filas_con_modo
FROM public.evaluations WHERE exam_mode IS NOT NULL
UNION ALL
SELECT 'evaluations.policy_json', COUNT(*)
FROM public.evaluations WHERE policy_json IS NOT NULL;


-- ===== csharp/migration-exam-pdf.sql =====

-- ============================================================
--  Migracion: PDF de enunciado por evaluacion
--  - evaluations.exam_pdf_path : path del objeto en Storage que apunta al
--    PDF del enunciado (ej 'eval-49.pdf'). NULL => la evaluacion no tiene PDF.
--  - Bucket privado 'exam-pdfs' en Storage. El panel (authenticated) sube,
--    reemplaza y borra; el cliente C# (anon) lo descarga via RLS SELECT.
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- 1. Columna nueva ------------------------------------------------------
ALTER TABLE public.evaluations
  ADD COLUMN IF NOT EXISTS exam_pdf_path TEXT;

-- 2. Bucket privado de Storage -----------------------------------------
-- public=false => no hay URL publica directa: toda descarga pasa por RLS.
INSERT INTO storage.buckets (id, name, public)
VALUES ('exam-pdfs', 'exam-pdfs', false)
ON CONFLICT (id) DO NOTHING;

-- 3. Politicas RLS sobre storage.objects (bucket 'exam-pdfs') -----------
-- SELECT (descarga): anon + authenticated. El cliente del alumno usa la
-- anon key, asi que necesita poder leer el objeto del enunciado.
DROP POLICY IF EXISTS "exam_pdfs_select" ON storage.objects;
CREATE POLICY "exam_pdfs_select"
  ON storage.objects
  FOR SELECT
  TO anon, authenticated
  USING (bucket_id = 'exam-pdfs');

-- INSERT/UPDATE/DELETE (gestion): solo el panel (authenticated).
DROP POLICY IF EXISTS "exam_pdfs_insert" ON storage.objects;
CREATE POLICY "exam_pdfs_insert"
  ON storage.objects
  FOR INSERT
  TO authenticated
  WITH CHECK (bucket_id = 'exam-pdfs');

DROP POLICY IF EXISTS "exam_pdfs_update" ON storage.objects;
CREATE POLICY "exam_pdfs_update"
  ON storage.objects
  FOR UPDATE
  TO authenticated
  USING (bucket_id = 'exam-pdfs')
  WITH CHECK (bucket_id = 'exam-pdfs');

DROP POLICY IF EXISTS "exam_pdfs_delete" ON storage.objects;
CREATE POLICY "exam_pdfs_delete"
  ON storage.objects
  FOR DELETE
  TO authenticated
  USING (bucket_id = 'exam-pdfs');

-- 4. Verificacion -------------------------------------------------------
SELECT 'evaluations.exam_pdf_path' AS check, COUNT(*) AS filas_con_pdf
FROM public.evaluations WHERE exam_pdf_path IS NOT NULL
UNION ALL
SELECT 'storage.buckets exam-pdfs', COUNT(*)
FROM storage.buckets WHERE id = 'exam-pdfs';


-- ===== csharp/migration-exam-pdf-scope.sql =====

-- ============================================================
--  Migracion: acotar la lectura anon del bucket exam-pdfs
--  (cierra HIGH sec-backend-04: fuga del enunciado completo).
--
--  ANTES: la policy exam_pdfs_select dejaba a CUALQUIER anon listar y
--  descargar TODOS los PDF de TODAS las secciones (filtro solo por
--  bucket_id), con nombre predecible (eval-<id>.pdf), incluso ANTES de
--  activarse la evaluacion -> fuga del contenido del examen.
--
--  AHORA: anon solo puede descargar el objeto si su nombre coincide con
--  el exam_pdf_path de una evaluacion ACTIVA. El profe (authenticated)
--  sigue viendo todo (para previsualizar/gestionar). No requiere cambios
--  en el cliente: el alumno abre el enunciado cuando la evaluacion esta
--  activa, que es justo cuando esta policy lo permite.
--
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- Se reemplaza la policy unica permisiva por DOS policies role-scoped
-- (varias policies permisivas para el mismo comando se combinan con OR).

-- Quitar la policy vieja (anon+authenticated, solo bucket_id).
DROP POLICY IF EXISTS "exam_pdfs_select" ON storage.objects;

-- Profe (authenticated): lee todo el bucket (subir / reemplazar / revisar).
DROP POLICY IF EXISTS "exam_pdfs_select_teacher" ON storage.objects;
CREATE POLICY "exam_pdfs_select_teacher"
  ON storage.objects
  FOR SELECT
  TO authenticated
  USING (bucket_id = 'exam-pdfs');

-- Alumno (anon): solo el PDF de una evaluacion ACTIVA con exam_pdf_path.
DROP POLICY IF EXISTS "exam_pdfs_select_student" ON storage.objects;
CREATE POLICY "exam_pdfs_select_student"
  ON storage.objects
  FOR SELECT
  TO anon
  USING (
    bucket_id = 'exam-pdfs'
    AND name IN (
      SELECT exam_pdf_path
      FROM public.evaluations
      WHERE active = true
        AND exam_pdf_path IS NOT NULL
    )
  );

-- ============================================================
--  RESIDUAL: mientras la evaluacion esta activa, cualquier portador de la
--  anon key puede descargar ESE PDF (es el enunciado en curso, destinado a
--  los alumnos que rinden). Lo que se cierra es la fuga PRE-examen y la de
--  OTRAS secciones/evaluaciones no activas. Acotar por alumno/seccion
--  exige binding de identidad real (JWT por dispositivo), igual que el
--  resto de A01 (ver migration-rls-identity-hardening.sql).
-- ============================================================

-- ============================================================
--  VERIFICACION
-- ============================================================
-- Esperado: la vieja 'exam_pdfs_select' ausente (0); las dos nuevas presentes (2).
SELECT 'exam_pdfs_select (vieja, esperado 0)' AS check, COUNT(*) AS n
  FROM pg_policies
  WHERE schemaname = 'storage' AND tablename = 'objects'
    AND policyname = 'exam_pdfs_select'
UNION ALL
SELECT 'exam_pdfs_select_teacher/student (esperado 2)', COUNT(*)
  FROM pg_policies
  WHERE schemaname = 'storage' AND tablename = 'objects'
    AND policyname IN ('exam_pdfs_select_teacher', 'exam_pdfs_select_student');


-- ===== csharp/migration-exam-time.sql =====

-- ============================================================
--  Migracion: tiempo de examen por evaluacion + reloj de servidor
--  - evaluations.ends_at : hora FIJA de termino del examen, por
--    evaluacion, definida por el docente (analoga a exam_pdf_path /
--    exam_mode). NULL => la evaluacion no tiene cuenta regresiva
--    (el widget no muestra contador).
--  - RPC get_exam_time(p_evaluation_id) : devuelve la hora del
--    servidor (clock_timestamp()) + el ends_at de la evaluacion, para
--    que el widget del cliente compute el tiempo restante SIN confiar
--    en el reloj local de la maquina.
--  No toca RLS: evaluations ya tiene policies (anon lee solo activas,
--  authenticated CRUD). Ver decision de SECURITY abajo.
--  Idempotente. Correr en Supabase SQL Editor.
--
--  ORDEN DE EJECUCION: correr DESPUES de migration-multi-evaluation.sql
--  (provee la tabla evaluations y su RLS anon_read_evaluations
--  USING (active = true)) y junto al resto de las migraciones exam-*
--  (exam-mode / exam-pdf / exam-pdf-scope) que tambien ALTERan
--  evaluations de forma aditiva.
-- ============================================================

-- ============================================================
--  1. Columna nueva
--  ends_at nace NULL para todas las filas existentes (forward-
--  compatible): sin cuenta regresiva hasta que el docente fije una
--  hora de termino desde el panel. NULL = el widget no muestra
--  contador. Mismo patron aditivo que exam_pdf_path / exam_mode.
-- ============================================================

ALTER TABLE public.evaluations
  ADD COLUMN IF NOT EXISTS ends_at TIMESTAMPTZ;

-- ============================================================
--  2. RPC get_exam_time : reloj de servidor + ends_at
--
--  DECISION DE SECURITY: SECURITY INVOKER (least-privilege).
--  La funcion corre con los privilegios y la RLS del rol que la
--  invoca, de modo que el SELECT interno queda sujeto a la policy
--  anon_read_evaluations (USING active = true). Asi:
--    - anon obtiene server_now + ends_at SOLO para evaluaciones
--      ACTIVAS (justo cuando el widget lo necesita); para una
--      evaluacion inactiva o inexistente el SELECT no ve la fila y
--      la RPC devuelve 0 filas (el widget no muestra contador).
--    - authenticated (panel) ve cualquier evaluacion via
--      auth_all_evaluations.
--  El cliente del alumno ya lee public.evaluations con la anon key
--  (GET evaluations?...&select=*), o sea anon ya tiene SELECT a nivel
--  de tabla; por eso INVOKER funciona sin GRANT adicional y NO hace
--  falta SECURITY DEFINER. Se evita DEFINER a proposito: bypassearia
--  la RLS y filtraria ends_at de evaluaciones NO activas a anon, sin
--  necesidad. Mismo criterio active-only que exam-pdf-scope.sql.
--
--  A DIFERENCIA de get_my_enrollment (DEFINER, porque enrollments es
--  authenticated-ONLY y guarda PII), aca la tabla ya tiene lectura
--  anon acotada por active, asi que INVOKER es suficiente y mas seguro.
--
--  NOTA: NO lleva guard de identidad FASE-2 (jwt_github_username()).
--  ends_at + server_now NO son sensibles, y exigir el claim cegaria al
--  widget ANTES del enrolamiento. Por eso esta RPC no va en el bloque
--  FASE 2 de migrations.order.
--
--  Se usa clock_timestamp() (hora real del statement), NO now() /
--  transaction_timestamp() (hora del inicio de la transaccion), para
--  entregar el instante mas fresco posible del servidor.
--
--  DROP previo de la firma para idempotencia ante un cambio futuro del
--  RETURNS TABLE (CREATE OR REPLACE no puede cambiar el tipo de
--  retorno). Mismo patron que get_my_enrollment.
-- ============================================================

DROP FUNCTION IF EXISTS public.get_exam_time(BIGINT);

CREATE OR REPLACE FUNCTION public.get_exam_time(
  p_evaluation_id BIGINT
) RETURNS TABLE (
  server_now TIMESTAMPTZ,
  ends_at TIMESTAMPTZ
)
LANGUAGE sql
SECURITY INVOKER
SET search_path = public
AS $$
  SELECT clock_timestamp(), e.ends_at
  FROM public.evaluations e
  WHERE e.id = p_evaluation_id;
$$;

GRANT EXECUTE ON FUNCTION public.get_exam_time(BIGINT)
  TO anon, authenticated;

-- ============================================================
--  3. VERIFICACION
--     1) La columna evaluations.ends_at existe (esperado: 1).
--     2) La RPC get_exam_time existe y es ejecutable por anon
--        (esperado: 1).
-- ============================================================

SELECT 'evaluations.ends_at existe' AS check, COUNT(*) AS n
  FROM information_schema.columns
  WHERE table_schema = 'public'
    AND table_name = 'evaluations'
    AND column_name = 'ends_at'
UNION ALL
SELECT 'get_exam_time EXECUTE anon', COUNT(*)
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = 'public'
    AND p.proname = 'get_exam_time'
    AND has_function_privilege('anon', p.oid, 'EXECUTE');


-- ===== csharp/migration-pc-overrides.sql =====

-- ============================================================
--  Migracion: override de desbloqueo POR PC (por nombre de maquina)
--
--  Permite al profe desbloquear internet + pantalla roja de UN PC
--  identificado por su NOMBRE de maquina, sin depender del usuario
--  que tenga la sesion abierta (en el lab los alumnos rotan de PC).
--  El cliente C# lee public.pc_overrides por pc_name y, en <20s,
--  libera internet y/o saca la pantalla roja de ESE PC. Para que el
--  PC vuelva a poder bloquearse, el profe "reactiva monitoreo"
--  (unblock_internet=false, unblock_screen=false) desde el panel.
--
--  Contrato FIJO (el cliente C# lee estos nombres igual):
--    pc_name TEXT PRIMARY KEY, unblock_internet BOOLEAN NOT NULL
--    DEFAULT false, unblock_screen BOOLEAN NOT NULL DEFAULT false,
--    updated_at TIMESTAMPTZ DEFAULT NOW(), updated_by TEXT.
--
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- ============================================================
--  1. Tabla pc_overrides
--  Una fila por PC (pc_name como PK). Las dos flags nacen en false:
--  una fila sin override no desbloquea nada (el PC sigue bajo las
--  reglas globales / por-evaluacion). El profe las pone en true para
--  liberar ESE PC.
-- ============================================================

CREATE TABLE IF NOT EXISTS public.pc_overrides (
  pc_name TEXT PRIMARY KEY,
  unblock_internet BOOLEAN NOT NULL DEFAULT false,
  unblock_screen BOOLEAN NOT NULL DEFAULT false,
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  updated_by TEXT
);

-- ============================================================
--  2. ROW LEVEL SECURITY
--  Mismo patron que el resto del control: anon + authenticated LEEN
--  (el cliente pollea su override por pc_name), authenticated ALL
--  escribe (el panel hace upsert/update). Idempotente via
--  DROP POLICY IF EXISTS + CREATE.
-- ============================================================

ALTER TABLE public.pc_overrides ENABLE ROW LEVEL SECURITY;

-- SELECT para anon (cliente) y authenticated (panel).
DROP POLICY IF EXISTS "anon_read_pc_overrides" ON public.pc_overrides;
CREATE POLICY "anon_read_pc_overrides" ON public.pc_overrides
  FOR SELECT TO anon, authenticated USING (true);

-- ALL (INSERT/UPDATE/DELETE) solo para el panel autenticado.
DROP POLICY IF EXISTS "auth_all_pc_overrides" ON public.pc_overrides;
CREATE POLICY "auth_all_pc_overrides" ON public.pc_overrides
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- ============================================================
--  3. REALTIME
--  Publica pc_overrides para que el cliente reciba en vivo el
--  desbloqueo (o la reactivacion de monitoreo) de su PC sin esperar
--  al siguiente poll. DO-block guardado: no falla si ya estaba en la
--  publicacion.
-- ============================================================

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_publication_tables
    WHERE pubname = 'supabase_realtime'
      AND schemaname = 'public'
      AND tablename = 'pc_overrides'
  ) THEN
    EXECUTE 'ALTER PUBLICATION supabase_realtime ADD TABLE public.pc_overrides';
    RAISE NOTICE 'Realtime habilitado para public.pc_overrides';
  ELSE
    RAISE NOTICE 'public.pc_overrides ya estaba en supabase_realtime (sin cambios)';
  END IF;
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- ============================================================
--  4. VERIFICACION
-- ============================================================

SELECT 'pc_overrides (total)' AS check, COUNT(*) AS n
  FROM public.pc_overrides
UNION ALL
SELECT 'pc_overrides desbloqueados', COUNT(*)
  FROM public.pc_overrides
  WHERE unblock_internet OR unblock_screen;


-- ===== csharp/migration-rls-identity-hardening.sql =====

-- ============================================================
--  Migracion: HARDENING de RLS/RPC para cerrar A01 (Broken Access
--  Control) sin romper el cliente en vivo (temporada de examenes).
--  Idempotente. Correr en Supabase SQL Editor.
--
--  CONTEXTO DE IDENTIDAD (leer antes de juzgar el alcance):
--  El cliente del alumno usa la ANON KEY COMPARTIDA. El github_username
--  y el pc_name van como PARAMETRO auto-asertado; NO hay sesion Supabase
--  por-alumno ni auth.uid() invocable. Por lo tanto NO existe binding
--  real de identidad a nivel RLS: cualquier anon puede afirmar cualquier
--  username. Esta migracion NO pretende cerrar ese gap (ver bloque
--  RESIDUAL al final); su objetivo es REDUCIR EL RADIO DE IMPACTO con
--  cambios de BAJO RIESGO que no rompen el cliente:
--
--    1. Eliminar el vector de SOBREESCRITURA / borrado de filas ajenas:
--       revocar el UPDATE (y dejar el DELETE ya denegado) directo de anon
--       sobre assignment_acceptances y assignment_submissions, donde
--       USING(true)/WITH CHECK(true) hoy deja a cualquier anon PISAR la
--       fila de OTRO alumno. El cliente nunca escribe estas tablas
--       directo: usa SIEMPRE las RPC SECURITY DEFINER record_acceptance /
--       record_submission (ver mapa de superficie de escritura). Por eso
--       revocar el INSERT/UPDATE directo NO rompe nada.
--
--    2. Forzar que TODA escritura de alumno sobre esas tablas pase por la
--       RPC, que hace UPSERT keyed por (github_username, assignment_id) y
--       por construccion NUNCA toca la fila de otra identidad salvo la que
--       el llamador afirma (residual inevitable, documentado).
--
--    3. Mantener cheat_events / student_activity / browser_history como
--       INSERT-only para anon (sin UPDATE/DELETE): no tienen RPC, el
--       cliente inserta directo, asi que solo blindamos contra mutacion
--       posterior de filas ajenas.
--
--    4. Endurecer las RPC anon-callables con un guard de identidad-presente
--       (rechazo silencioso de escrituras sin username/pc_name) sin alterar
--       su firma exacta (nombre + tipos + orden + defaults), que es
--       load-bearing para el POST del cliente.
--
--  NO se toca: heartbeat (presencia efimera, 9-arg load-bearing cada 20s),
--  process_alerts INSERT directo de anon (DROP DIFERIDO a proposito por
--  clientes v2.5.0 vivos), ni ningun GRANT/firma de RPC. Ver notas inline.
-- ============================================================


-- ============================================================
--  A. assignment_acceptances
--     Cierra: anon podia PISAR (UPDATE) la aceptacion de cualquier alumno
--     porque anon_update_acceptances usa USING(true) WITH CHECK(true) sin
--     binding de identidad. Tambien podia crear filas directo.
--     Por que NO rompe: el cliente registra aceptaciones EXCLUSIVAMENTE
--     via RPC record_acceptance (SECURITY DEFINER, hace UPSERT). De esta
--     tabla solo hace GET (lectura). Mantenemos anon_read_acceptances.
-- ============================================================

-- Revocar UPDATE directo de anon (vector de sobreescritura de fila ajena).
DROP POLICY IF EXISTS "anon_update_acceptances" ON public.assignment_acceptances;

-- Revocar INSERT directo de anon: la unica via de escritura es la RPC.
-- (La RPC es SECURITY DEFINER: inserta aunque no exista policy anon.)
DROP POLICY IF EXISTS "anon_insert_acceptances" ON public.assignment_acceptances;

-- Re-afirmar la lectura anon (sin cambios; necesaria para el cliente).
DROP POLICY IF EXISTS "anon_read_acceptances" ON public.assignment_acceptances;
CREATE POLICY "anon_read_acceptances" ON public.assignment_acceptances
  FOR SELECT TO anon, authenticated USING (true);

-- NOTA DELETE: no existe policy FOR DELETE de anon, por lo que el DELETE
-- ya esta denegado bajo RLS. No hace falta accion.
--
-- ROLLBACK (si se detecta un cliente legacy que escribia directo):
--   CREATE POLICY "anon_insert_acceptances" ON public.assignment_acceptances
--     FOR INSERT WITH CHECK (true);
--   CREATE POLICY "anon_update_acceptances" ON public.assignment_acceptances
--     FOR UPDATE USING (true) WITH CHECK (true);


-- ============================================================
--  B. assignment_submissions
--     Cierra y por que NO rompe: identico a (A). El cliente entrega via
--     RPC record_submission. Mantenemos solo la lectura anon.
-- ============================================================

DROP POLICY IF EXISTS "anon_update_submissions" ON public.assignment_submissions;
DROP POLICY IF EXISTS "anon_insert_submissions" ON public.assignment_submissions;

DROP POLICY IF EXISTS "anon_read_submissions" ON public.assignment_submissions;
CREATE POLICY "anon_read_submissions" ON public.assignment_submissions
  FOR SELECT TO anon, authenticated USING (true);

-- ROLLBACK:
--   CREATE POLICY "anon_insert_submissions" ON public.assignment_submissions
--     FOR INSERT WITH CHECK (true);
--   CREATE POLICY "anon_update_submissions" ON public.assignment_submissions
--     FOR UPDATE USING (true) WITH CHECK (true);


-- ============================================================
--  C. cheat_events / student_activity / browser_history
--     Estas tablas NO tienen RPC: el cliente inserta DIRECTO (writes
--     #6/#7/#8 del mapa). Las dejamos INSERT-only para anon. Hoy ya NO
--     tienen policy de UPDATE/DELETE, asi que la sobreescritura de filas
--     ajenas ya esta denegada; aqui solo lo BLINDAMOS de forma defensiva
--     e idempotente (por si una DB de produccion tuviera alguna policy
--     anon de mutacion creada a mano fuera del estado canonico) y
--     re-afirmamos el INSERT que el cliente necesita.
--     Por que NO rompe: el INSERT anon sigue vivo con las mismas columnas.
-- ============================================================

-- cheat_events
DROP POLICY IF EXISTS "anon_update_cheat" ON public.cheat_events;
DROP POLICY IF EXISTS "anon_delete_cheat" ON public.cheat_events;
DROP POLICY IF EXISTS "anon_insert_cheat" ON public.cheat_events;
CREATE POLICY "anon_insert_cheat" ON public.cheat_events
  FOR INSERT WITH CHECK (true);

-- student_activity
DROP POLICY IF EXISTS "anon_update_activity" ON public.student_activity;
DROP POLICY IF EXISTS "anon_delete_activity" ON public.student_activity;
DROP POLICY IF EXISTS "anon_insert_activity" ON public.student_activity;
CREATE POLICY "anon_insert_activity" ON public.student_activity
  FOR INSERT WITH CHECK (true);

-- browser_history
DROP POLICY IF EXISTS "anon_update_browser" ON public.browser_history;
DROP POLICY IF EXISTS "anon_delete_browser" ON public.browser_history;
DROP POLICY IF EXISTS "anon_insert_browser" ON public.browser_history;
CREATE POLICY "anon_insert_browser" ON public.browser_history
  FOR INSERT WITH CHECK (true);


-- ============================================================
--  D. process_alerts  (NO SE TOCA -- DROP DIFERIDO A PROPOSITO)
--     El INSERT directo de anon sobre process_alerts (anon_insert_alerts)
--     puede seguir vivo en una DB de produccion porque clientes v2.5.0 aun
--     insertan directo y se tragan el error en catch silencioso. Quitarlo
--     aqui haria desaparecer alertas SIN AVISO en cada PC no actualizado.
--     La RPC report_process_alert (SECURITY DEFINER, rate-limit 30s) y el
--     INSERT directo COEXISTEN sin problema. El DROP definitivo va recien
--     cuando PR2 (cliente -> RPC) este desplegado en TODAS las maquinas.
--     Ver la secuencia en migration-blocklist.sql seccion 5 y la nota en
--     setup-supabase.sql. (Sin cambios en esta migracion.)
-- ============================================================
-- (intencionalmente vacio)


-- ============================================================
--  E. ENDURECIMIENTO DE RPCs ANON-CALLABLES
--     Se re-afirman con CREATE OR REPLACE (firma EXACTA e intacta) los
--     UPSERT keyed para PIN del comportamiento seguro canonico + un guard
--     de IDENTIDAD-PRESENTE: si el llamador no afirma identidad (username/
--     pc_name vacio o NULL) la RPC hace RETURN silencioso (no escribe, no
--     lanza error -> no rompe el cliente, que envuelve el POST en
--     try/catch). Esto evita filas "fantasma" sin identidad atribuible.
--     RESIDUAL: un anon puede afirmar el username/pc_name de OTRO alumno;
--     eso NO es cerrable con RLS (ver bloque RESIDUAL). El UPSERT sigue
--     keyed por (github_username, assignment_id) / (pc_name, github_username)
--     asi que la escritura nunca toca una fila de identidad distinta a la
--     afirmada.
-- ============================================================

-- E.1 record_acceptance: UPSERT keyed por (github_username, assignment_id).
--     Firma IDENTICA a migration-acceptances.sql (7 params). Solo cambia el
--     cuerpo para sumar el guard de identidad-presente.
CREATE OR REPLACE FUNCTION public.record_acceptance(
  p_github_username TEXT,
  p_assignment_id BIGINT,
  p_assignment_title TEXT DEFAULT NULL,
  p_section TEXT DEFAULT NULL,
  p_repo_name TEXT DEFAULT NULL,
  p_repo_url TEXT DEFAULT NULL,
  p_evaluation_id BIGINT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  -- Guard de identidad-presente: sin username no se registra (no-op).
  IF p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  INSERT INTO public.assignment_acceptances
    (github_username, assignment_id, assignment_title, section, repo_name, repo_url, evaluation_id, accepted_at)
  VALUES
    (p_github_username, p_assignment_id, p_assignment_title, p_section, p_repo_name, p_repo_url, p_evaluation_id, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET assignment_title = EXCLUDED.assignment_title,
      section          = EXCLUDED.section,
      repo_name        = EXCLUDED.repo_name,
      repo_url         = EXCLUDED.repo_url,
      evaluation_id    = COALESCE(EXCLUDED.evaluation_id, public.assignment_acceptances.evaluation_id),
      accepted_at      = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_acceptance(TEXT,BIGINT,TEXT,TEXT,TEXT,TEXT,BIGINT)
  TO anon, authenticated;

-- E.2 record_submission: UPSERT keyed por (github_username, assignment_id).
--     Firma IDENTICA a migration-submissions.sql (4 params).
CREATE OR REPLACE FUNCTION public.record_submission(
  p_assignment_id BIGINT,
  p_github_username TEXT,
  p_repo_url TEXT,
  p_status TEXT DEFAULT 'submitted'
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  -- Guard de identidad-presente.
  IF p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  INSERT INTO public.assignment_submissions
    (assignment_id, github_username, repo_url, status, submitted_at)
  VALUES
    (p_assignment_id, p_github_username, p_repo_url, p_status, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET repo_url      = EXCLUDED.repo_url,
      status        = EXCLUDED.status,
      submitted_at  = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_submission(BIGINT,TEXT,TEXT,TEXT)
  TO anon, authenticated;

-- E.3 report_self_lock: solo fija active=true (el alumno NO puede
--     auto-liberarse; el release es authenticated). Firma IDENTICA a
--     migration-self-lock.sql (5 params). UPSERT keyed por
--     (pc_name, github_username).
CREATE OR REPLACE FUNCTION public.report_self_lock(
  p_pc_name TEXT,
  p_github_username TEXT,
  p_section TEXT DEFAULT NULL,
  p_reason TEXT DEFAULT NULL,
  p_source TEXT DEFAULT 'trap'
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Guard de identidad-presente: sin pc_name + username no hay a quien
  -- atribuir el auto-lock (no-op). Reduce ruido, no cierra el residual.
  IF p_pc_name IS NULL OR btrim(p_pc_name) = ''
     OR p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  INSERT INTO public.targeted_lockdowns
    (pc_name, github_username, active, reason, source, created_at, released_at)
  VALUES
    (p_pc_name, p_github_username, true, p_reason,
     COALESCE(p_source, 'trap'), NOW(), NULL)
  ON CONFLICT (pc_name, github_username) DO UPDATE
  SET active      = true,
      reason      = EXCLUDED.reason,
      source      = EXCLUDED.source,
      created_at  = NOW(),
      released_at = NULL;
END;
$$;
GRANT EXECUTE ON FUNCTION public.report_self_lock(TEXT, TEXT, TEXT, TEXT, TEXT)
  TO anon, authenticated;

-- E.4 report_process_alert: rate-limit 30s por (pc_name, process_name).
--     Firma IDENTICA a migration-blocklist.sql / setup-supabase.sql
--     (6 params, ORDEN load-bearing: github_username, pc_name, section,
--     process_name, window_title, evaluation_id).
CREATE OR REPLACE FUNCTION public.report_process_alert(
  p_github_username TEXT,
  p_pc_name TEXT,
  p_section TEXT,
  p_process_name TEXT,
  p_window_title TEXT,
  p_evaluation_id BIGINT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  -- Guard de identidad-presente: la alerta se atribuye a (pc_name +
  -- process_name); sin esos campos no se registra (no-op).
  IF p_pc_name IS NULL OR btrim(p_pc_name) = ''
     OR p_process_name IS NULL OR btrim(p_process_name) = '' THEN
    RETURN;
  END IF;

  -- Rate-limit: descartar duplicado dentro de la ventana de 30s.
  IF EXISTS (
    SELECT 1 FROM public.process_alerts
    WHERE pc_name = p_pc_name
      AND process_name = p_process_name
      AND detected_at > NOW() - INTERVAL '30 seconds'
  ) THEN
    RETURN;
  END IF;

  INSERT INTO public.process_alerts
    (pc_name, github_username, section, process_name, window_title, evaluation_id, detected_at)
  VALUES
    (p_pc_name, p_github_username, p_section, p_process_name, p_window_title, p_evaluation_id, NOW());
END;
$$;
GRANT EXECUTE ON FUNCTION public.report_process_alert(TEXT,TEXT,TEXT,TEXT,TEXT,BIGINT)
  TO anon, authenticated;


-- ============================================================
--  RESIDUAL CONOCIDO (NO cerrable solo con RLS por falta de identidad real)
--
--  Como el cliente usa la ANON KEY compartida y el github_username/pc_name
--  van auto-asertados por parametro, persisten estos vectores que ESTA
--  migracion NO puede cerrar (se documentan para el siguiente PR):
--
--   R1. Suplantacion de identidad en RPC: un anon puede llamar
--       record_acceptance / record_submission / report_self_lock /
--       report_process_alert afirmando el username/pc_name de OTRO alumno.
--       Impacto acotado: las RPC son keyed-upsert, asi que a lo sumo se
--       crea/pisa la fila DE LA IDENTIDAD AFIRMADA (p.ej. marcar una
--       entrega a nombre de un tercero, o auto-bloquear la pantalla de un
--       tercero via report_self_lock con su pc_name+username). El guard de
--       identidad-presente solo descarta escrituras SIN identidad, no las
--       de identidad ajena.
--
--   R2. heartbeat (presencia, online_clients) tiene el mismo gap; no se
--       endurece aqui por ser dato efimero y por su firma de 9 args
--       load-bearing cada 20s (riesgo > beneficio).
--
--   R3. Lecturas anon amplias: anon_read_targeted / anon_read_acceptances /
--       anon_read_submissions usan USING(true), de modo que un anon puede
--       LEER filas de otros alumnos. Acotar la lectura requiere binding de
--       identidad y rompe el cliente actual, asi que se deja como residual.
--
--  RECOMENDACION DE FONDO (trabajo futuro, fuera de esta migracion):
--  emitir un JWT POR DISPOSITIVO con un claim de identidad (device_id /
--  github_username verificado) via una Edge Function de enrolamiento, en
--  vez de la anon key compartida. Con ese JWT, las RPC y las policies
--  pueden comparar el parametro afirmado contra el claim (auth.jwt() ->>
--  'github_username') y RECHAZAR la suplantacion server-side, cerrando
--  R1/R2/R3 de raiz. Mientras tanto, esta migracion solo reduce el radio
--  de impacto (sobreescritura/borrado de filas ajenas y filas sin
--  identidad).
-- ============================================================


-- ============================================================
--  F. VERIFICACION
--     1) Las policies de mutacion directa de anon sobre acceptances/
--        submissions deben estar AUSENTES (esperado: 0 filas).
--     2) El INSERT-only de anon sobre cheat/activity/browser debe seguir
--        presente (esperado: 3 policies INSERT, 0 de UPDATE/DELETE anon).
--     3) Las 4 RPC endurecidas deben existir con EXECUTE para anon.
-- ============================================================

-- 1) No deben quedar policies de INSERT/UPDATE/DELETE de anon en estas tablas.
SELECT 'F1 mutacion directa anon (esperado 0)' AS check,
       COUNT(*) AS policies_restantes
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename IN ('assignment_acceptances', 'assignment_submissions')
  AND cmd IN ('INSERT', 'UPDATE', 'DELETE');

-- 2) INSERT-only de anon vigente; sin UPDATE/DELETE de anon.
SELECT 'F2 insert anon vigente (esperado 3)' AS check,
       COUNT(*) FILTER (WHERE cmd = 'INSERT') AS inserts,
       COUNT(*) FILTER (WHERE cmd IN ('UPDATE', 'DELETE')) AS mutaciones_anon
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename IN ('cheat_events', 'student_activity', 'browser_history')
  AND policyname LIKE 'anon_%';

-- 3) RPC endurecidas presentes y ejecutables por anon.
SELECT 'F3 grant EXECUTE a anon' AS check, p.proname AS rpc
FROM pg_proc p
JOIN pg_namespace n ON n.oid = p.pronamespace
WHERE n.nspname = 'public'
  AND p.proname IN ('record_acceptance', 'record_submission',
                    'report_self_lock', 'report_process_alert')
  AND has_function_privilege('anon', p.oid, 'EXECUTE')
ORDER BY p.proname;


-- ===== csharp/migration-jwt-identity.sql =====

-- ⚠️ FASE 2: EXIGE identidad verificada. RECHAZA clientes sin JWT (anon crudo).
-- NO CORRER hasta: (1) 0 clientes <2.7.20 activos (ENT-23) y (2) fuera de ventana de examen.
-- ============================================================
--  Migracion: JWT IDENTITY HARDENING -- FASE 2 (breaking: exige claim).
--  Idempotente. Correr en Supabase SQL Editor.
--
--  OBJETIVO:
--  Cerrar la suplantacion de identidad (residual R1/R3 de
--  migration-rls-identity-hardening.sql) usando la IDENTIDAD VERIFICADA
--  que viaja en el JWT, sin romper a ningun cliente en vivo.
--
--  COMO LLEGA LA IDENTIDAD VERIFICADA:
--  La Edge Function `enroll-identity` (POST /functions/v1/enroll-identity)
--  recibe el github_token del device-flow del alumno, valida ese token
--  contra GET https://api.github.com/user y, con el login/id VERIFICADOS,
--  emite un JWT HS256 firmado con el JWT Secret legacy del proyecto. El
--  JWT lleva claims:
--      role            = "anon"   (NO "authenticated": mantiene las
--                                  policies anon actuales; "authenticated"
--                                  daria god-mode de profe)
--      aud             = "authenticated"
--      iss             = "exam-enroll"
--      github_username = <login verificado>
--      github_id       = <id verificado>
--      iat / exp       = ahora / ahora + 12h
--  El cliente porta ese JWT como `Authorization: Bearer <jwt>` (mas la
--  apikey anon) en TODAS las llamadas REST/RPC. PostgREST expone esos
--  claims a la sesion SQL via `request.jwt.claims`, asi que las RPC y las
--  policies pueden leer el github_username VERIFICADO y compararlo contra
--  el que el cliente AFIRMA por parametro/columna.
--
--  REGLA DE FASE 2 (EXIGE EL CLAIM VERIFICADO):
--    - claim github_username NULL/ausente o vacio (cliente sin enrolar o
--      con anon key cruda como Bearer) -> RECHAZADO (RPC: RETURN no-op;
--      policy: false).
--    - claim github_username presente pero DISTINTO del username afirmado
--      -> RECHAZADO.
--    - claim github_username presente e IGUAL al afirmado -> PERMITIDO.
--  De este modo SOLO un cliente con IDENTIDAD VERIFICADA puede escribir, y
--  unicamente a su propio nombre: se cierra de raiz la suplantacion (R1/R3).
--
--  ADVERTENCIA: esto ROMPE a clientes viejos sin JWT. No aplicar hasta que
--  no queden clientes <2.7.20 activos (ENT-23). El bloque al final conserva
--  la nota de ROLLBACK a la regla FASE 1 (backward-compat).
--
--  Esta migracion NO cambia firmas ni grants de RPC, NO toca otras tablas
--  ni otras policies, y conserva el cuerpo completo de cada RPC (guard de
--  identidad-presente, UPSERT keyed, rate-limit de process_alert).
-- ============================================================


-- ============================================================
--  0. HELPER: identidad verificada del JWT.
--     Devuelve el claim github_username del JWT verificado, o NULL si no
--     hay JWT/claim (cliente viejo con anon key cruda) o si el parseo
--     falla. STABLE: depende solo de la sesion, no escribe.
-- ============================================================
CREATE OR REPLACE FUNCTION public.jwt_github_username()
RETURNS TEXT
LANGUAGE plpgsql
STABLE
SET search_path = public
AS $$
DECLARE
  v_claim TEXT;
BEGIN
  -- current_setting(..., true) devuelve NULL si el GUC no esta seteado.
  -- El ::json ->> extrae el claim; cualquier error de parseo cae al EXCEPTION.
  v_claim := current_setting('request.jwt.claims', true)::json ->> 'github_username';
  RETURN v_claim;
EXCEPTION
  WHEN OTHERS THEN
    RETURN NULL;
END;
$$;

GRANT EXECUTE ON FUNCTION public.jwt_github_username() TO anon, authenticated;


-- ============================================================
--  A. RPCs ANON-CALLABLES: guard de IDENTIDAD-VERIFICADA.
--     CREATE OR REPLACE con la firma EXACTA de
--     migration-rls-identity-hardening.sql (nombre + tipos + orden +
--     defaults intactos; grants intactos). Se conserva todo el cuerpo
--     previo (guard de identidad-presente, UPSERT keyed, rate-limit) y se
--     SUMA el guard de identidad-verificada justo despues:
--
--         v := public.jwt_github_username();
--         IF v IS NULL OR v = '' OR v IS DISTINCT FROM p_github_username
--         THEN RETURN; END IF;   -- no-op silencioso; EXIGE claim verificado
--
--     Si el claim es NULL/ausente (cliente sin enrolar) la condicion
--     dispara y la escritura es RECHAZADA (FASE 2, ya no backward-compat).
-- ============================================================

-- A.1 record_acceptance (7 params). Firma IDENTICA.
CREATE OR REPLACE FUNCTION public.record_acceptance(
  p_github_username TEXT,
  p_assignment_id BIGINT,
  p_assignment_title TEXT DEFAULT NULL,
  p_section TEXT DEFAULT NULL,
  p_repo_name TEXT DEFAULT NULL,
  p_repo_url TEXT DEFAULT NULL,
  p_evaluation_id BIGINT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_jwt_user TEXT;
BEGIN
  -- Guard de identidad-presente: sin username no se registra (no-op).
  IF p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  -- Guard de identidad-verificada (FASE 2): se EXIGE el claim verificado.
  -- Claim presente y DISTINTO del afirmado -> rechazo silencioso. Claim
  -- NULL/ausente (cliente sin enrolar) -> RECHAZADO (ya no es backward-compat).
  v_jwt_user := public.jwt_github_username();
  IF v_jwt_user IS NULL OR v_jwt_user = ''
     OR v_jwt_user IS DISTINCT FROM p_github_username THEN
    RETURN;
  END IF;

  INSERT INTO public.assignment_acceptances
    (github_username, assignment_id, assignment_title, section, repo_name, repo_url, evaluation_id, accepted_at)
  VALUES
    (p_github_username, p_assignment_id, p_assignment_title, p_section, p_repo_name, p_repo_url, p_evaluation_id, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET assignment_title = EXCLUDED.assignment_title,
      section          = EXCLUDED.section,
      repo_name        = EXCLUDED.repo_name,
      repo_url         = EXCLUDED.repo_url,
      evaluation_id    = COALESCE(EXCLUDED.evaluation_id, public.assignment_acceptances.evaluation_id),
      accepted_at      = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_acceptance(TEXT,BIGINT,TEXT,TEXT,TEXT,TEXT,BIGINT)
  TO anon, authenticated;

-- A.2 record_submission (4 params). Firma IDENTICA.
CREATE OR REPLACE FUNCTION public.record_submission(
  p_assignment_id BIGINT,
  p_github_username TEXT,
  p_repo_url TEXT,
  p_status TEXT DEFAULT 'submitted'
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_jwt_user TEXT;
BEGIN
  -- Guard de identidad-presente.
  IF p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  -- Guard de identidad-verificada (FASE 2): se EXIGE el claim verificado.
  v_jwt_user := public.jwt_github_username();
  IF v_jwt_user IS NULL OR v_jwt_user = ''
     OR v_jwt_user IS DISTINCT FROM p_github_username THEN
    RETURN;
  END IF;

  INSERT INTO public.assignment_submissions
    (assignment_id, github_username, repo_url, status, submitted_at)
  VALUES
    (p_assignment_id, p_github_username, p_repo_url, p_status, NOW())
  ON CONFLICT (github_username, assignment_id) DO UPDATE
  SET repo_url      = EXCLUDED.repo_url,
      status        = EXCLUDED.status,
      submitted_at  = NOW();
END;
$$;
GRANT EXECUTE ON FUNCTION public.record_submission(BIGINT,TEXT,TEXT,TEXT)
  TO anon, authenticated;

-- A.3 report_self_lock (5 params). Firma IDENTICA.
CREATE OR REPLACE FUNCTION public.report_self_lock(
  p_pc_name TEXT,
  p_github_username TEXT,
  p_section TEXT DEFAULT NULL,
  p_reason TEXT DEFAULT NULL,
  p_source TEXT DEFAULT 'trap'
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_jwt_user TEXT;
BEGIN
  -- Guard de identidad-presente: sin pc_name + username no hay a quien
  -- atribuir el auto-lock (no-op). Reduce ruido, no cierra el residual.
  IF p_pc_name IS NULL OR btrim(p_pc_name) = ''
     OR p_github_username IS NULL OR btrim(p_github_username) = '' THEN
    RETURN;
  END IF;

  -- Guard de identidad-verificada (FASE 2): se EXIGE el claim verificado;
  -- evita que un alumno auto-bloquee la pantalla de un tercero, y ademas
  -- rechaza a cualquier cliente sin JWT (claim NULL/ausente).
  v_jwt_user := public.jwt_github_username();
  IF v_jwt_user IS NULL OR v_jwt_user = ''
     OR v_jwt_user IS DISTINCT FROM p_github_username THEN
    RETURN;
  END IF;

  INSERT INTO public.targeted_lockdowns
    (pc_name, github_username, active, reason, source, created_at, released_at)
  VALUES
    (p_pc_name, p_github_username, true, p_reason,
     COALESCE(p_source, 'trap'), NOW(), NULL)
  ON CONFLICT (pc_name, github_username) DO UPDATE
  SET active      = true,
      reason      = EXCLUDED.reason,
      source      = EXCLUDED.source,
      created_at  = NOW(),
      released_at = NULL;
END;
$$;
GRANT EXECUTE ON FUNCTION public.report_self_lock(TEXT, TEXT, TEXT, TEXT, TEXT)
  TO anon, authenticated;

-- A.4 report_process_alert (6 params, ORDEN load-bearing). Firma IDENTICA.
CREATE OR REPLACE FUNCTION public.report_process_alert(
  p_github_username TEXT,
  p_pc_name TEXT,
  p_section TEXT,
  p_process_name TEXT,
  p_window_title TEXT,
  p_evaluation_id BIGINT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_jwt_user TEXT;
BEGIN
  -- Guard de identidad-presente: la alerta se atribuye a (pc_name +
  -- process_name); sin esos campos no se registra (no-op).
  IF p_pc_name IS NULL OR btrim(p_pc_name) = ''
     OR p_process_name IS NULL OR btrim(p_process_name) = '' THEN
    RETURN;
  END IF;

  -- Guard de identidad-verificada (FASE 2): se EXIGE el claim verificado.
  -- Claim presente y distinto del afirmado -> no se registra la alerta a
  -- nombre del tercero. Claim NULL/ausente -> RECHAZADO (sin backward-compat).
  v_jwt_user := public.jwt_github_username();
  IF v_jwt_user IS NULL OR v_jwt_user = ''
     OR v_jwt_user IS DISTINCT FROM p_github_username THEN
    RETURN;
  END IF;

  -- Rate-limit: descartar duplicado dentro de la ventana de 30s.
  IF EXISTS (
    SELECT 1 FROM public.process_alerts
    WHERE pc_name = p_pc_name
      AND process_name = p_process_name
      AND detected_at > NOW() - INTERVAL '30 seconds'
  ) THEN
    RETURN;
  END IF;

  INSERT INTO public.process_alerts
    (pc_name, github_username, section, process_name, window_title, evaluation_id, detected_at)
  VALUES
    (p_pc_name, p_github_username, p_section, p_process_name, p_window_title, p_evaluation_id, NOW());
END;
$$;
GRANT EXECUTE ON FUNCTION public.report_process_alert(TEXT,TEXT,TEXT,TEXT,TEXT,BIGINT)
  TO anon, authenticated;


-- ============================================================
--  B. POLICIES anon_insert de INSERT DIRECTO (sin RPC):
--     cheat_events / student_activity / browser_history.
--     El WITH CHECK original (true) dejaba a cualquier anon insertar
--     cualquier identidad. FASE 2 lo endurece a:
--         <col_identidad> = jwt_github_username()
--     -> un cliente CON JWT solo puede insertar a SU nombre verificado.
--     -> un cliente sin JWT (claim NULL) queda RECHAZADO (sin compat).
--     DROP POLICY IF EXISTS + CREATE para idempotencia.
--
--     OJO con la columna de identidad por tabla:
--       cheat_events      -> columna `username`
--       student_activity  -> columna `github_username`
--       browser_history   -> columna `github_username`
-- ============================================================

-- B.1 cheat_events (columna de identidad: username).
DROP POLICY IF EXISTS "anon_insert_cheat" ON public.cheat_events;
CREATE POLICY "anon_insert_cheat" ON public.cheat_events
  FOR INSERT
  WITH CHECK ( username = public.jwt_github_username() );

-- B.2 student_activity (columna de identidad: github_username).
DROP POLICY IF EXISTS "anon_insert_activity" ON public.student_activity;
CREATE POLICY "anon_insert_activity" ON public.student_activity
  FOR INSERT
  WITH CHECK ( github_username = public.jwt_github_username() );

-- B.3 browser_history (columna de identidad: github_username).
DROP POLICY IF EXISTS "anon_insert_browser" ON public.browser_history;
CREATE POLICY "anon_insert_browser" ON public.browser_history
  FOR INSERT
  WITH CHECK ( github_username = public.jwt_github_username() );


-- ============================================================
--  FASE 2 -- APLICADA EN ESTE ARCHIVO ("REQUERIR EL CLAIM").
--
--  Este archivo YA contiene la version FASE 2: las 4 RPC y las 3 policies
--  anon_insert_* EXIGEN el claim github_username verificado. Cualquier
--  escritura sin JWT verificado queda denegada y se cierra de raiz la
--  suplantacion (R1/R3).
--
--  Precondicion para CORRERLO: TODOS los clientes en produccion estan
--  enrolados via enroll-identity y portan el JWT con github_username
--  verificado (no quedan clientes <2.7.20 activos, ENT-23) y se corre fuera
--  de la ventana de examen. Correrlo antes ROMPE a los clientes viejos que
--  aun usan la anon key cruda.
--
--  ROLLBACK A FASE 1 (backward-compat) si hay que revertir:
--
--  1) En las 4 RPC, restaurar el guard que PERMITE el claim NULL:
--
--         v_jwt_user := public.jwt_github_username();
--         IF v_jwt_user IS NOT NULL AND v_jwt_user <> ''
--            AND v_jwt_user IS DISTINCT FROM p_github_username THEN
--           RETURN;
--         END IF;
--
--  2) En las 3 policies anon_insert_*, reintroducir el "IS NULL OR":
--
--         -- cheat_events
--         WITH CHECK ( public.jwt_github_username() IS NULL
--                      OR username = public.jwt_github_username() );
--         -- student_activity
--         WITH CHECK ( public.jwt_github_username() IS NULL
--                      OR github_username = public.jwt_github_username() );
--         -- browser_history
--         WITH CHECK ( public.jwt_github_username() IS NULL
--                      OR github_username = public.jwt_github_username() );
-- ============================================================


-- ============================================================
--  C. VERIFICACION
--     1) El helper existe y es ejecutable por anon.
--     2) Las 4 RPC siguen presentes y ejecutables por anon (firmas/grants
--        intactos).
--     3) Las 3 policies anon_insert_* ya NO usan WITH CHECK (true): su
--        expresion referencia jwt_github_username y (FASE 2) ya NO contiene
--        "IS NULL" como rama de backward-compat (esperado: 3 filas).
-- ============================================================

-- 1) Helper presente y ejecutable por anon.
SELECT 'C1 helper jwt_github_username ejecutable por anon' AS check,
       has_function_privilege('anon', 'public.jwt_github_username()', 'EXECUTE') AS ok;

-- 2) RPC endurecidas presentes y ejecutables por anon (esperado: 4 filas).
SELECT 'C2 grant EXECUTE a anon' AS check, p.proname AS rpc
FROM pg_proc p
JOIN pg_namespace n ON n.oid = p.pronamespace
WHERE n.nspname = 'public'
  AND p.proname IN ('record_acceptance', 'record_submission',
                    'report_self_lock', 'report_process_alert')
  AND has_function_privilege('anon', p.oid, 'EXECUTE')
ORDER BY p.proname;

-- 3) Policies anon_insert_* endurecidas (FASE 2): su WITH CHECK referencia el
--    helper y ya NO contiene "IS NULL" (esperado: 3 filas, una por tabla).
SELECT 'C3 anon_insert con guard JWT FASE 2 (esperado 3)' AS check,
       tablename, policyname
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename IN ('cheat_events', 'student_activity', 'browser_history')
  AND policyname LIKE 'anon_insert_%'
  AND with_check ILIKE '%jwt_github_username%'
  AND with_check NOT ILIKE '%IS NULL%'
ORDER BY tablename;


-- ===== csharp/migration-heartbeat-identity.sql =====

-- ⚠️ FASE 2: EXIGE identidad verificada. RECHAZA clientes sin JWT (anon crudo).
-- NO CORRER hasta: (1) 0 clientes <2.7.20 activos (ENT-23) y (2) fuera de ventana de examen.
-- ============================================================
--  Migracion: identidad-verificada en heartbeat (sec-backend-05) -- FASE 2
--
--  Problema (MEDIUM): la RPC heartbeat acepta identidad arbitraria via
--  p_github_username auto-asertado -> spoofing/flooding de presencia
--  (un cliente puede registrar/actualizar presencia en nombre de otro).
--
--  Fix: agregar el MISMO guard de identidad-verificada que ya tienen las
--  otras 4 RPC (record_acceptance, record_submission, report_self_lock,
--  report_process_alert) via public.jwt_github_username() — helper que
--  devuelve el claim github_username verificado del JWT (o NULL para el
--  cliente viejo). Definido en csharp/migration-jwt-identity.sql.
--
--  FASE 2 (esta migracion, breaking): se EXIGE el claim github_username
--  verificado. Claim presente y DISTINTO del afirmado -> rechazo silencioso
--  (no-op). Claim NULL/ausente (cliente sin enrolar, sin el claim en el JWT)
--  -> RECHAZADO. Solo un cliente con identidad verificada registra presencia,
--  y unicamente a su propio nombre.
--
--  ADVERTENCIA: rompe a clientes viejos sin JWT; no aplicar hasta que no
--  queden clientes <2.7.20 activos (ENT-23) y fuera de ventana de examen.
--
--  ROLLBACK A FASE 1 (backward-compat) si hay que revertir: restaurar el
--  guard que PERMITE el claim NULL:
--      v_jwt_user := public.jwt_github_username();
--      IF v_jwt_user IS NOT NULL AND v_jwt_user <> ''
--         AND v_jwt_user IS DISTINCT FROM p_github_username THEN
--        RETURN;
--      END IF;
--
--  Idempotente. Correr en Supabase SQL Editor.
-- ============================================================

-- La firma es IDENTICA a la ultima definicion vigente (9 args, espejo de
-- csharp/migration-version-visibility.sql), por lo que CREATE OR REPLACE
-- reemplaza la funcion EN SU LUGAR: no crea un overload nuevo ni rompe a
-- PostgREST (300 ambiguous). Por eso NO hace falta DROP previo: una firma
-- distinta requeriria DROP, una identica no. El cuerpo (UPSERT a
-- online_clients ON CONFLICT (pc_name, github_username), columnas, COALESCE
-- de evaluation_id y app_version) queda INTACTO; solo se antepone el guard.
CREATE OR REPLACE FUNCTION public.heartbeat(
  p_pc_name TEXT,
  p_github_username TEXT,
  p_github_email TEXT DEFAULT NULL,
  p_section TEXT DEFAULT NULL,
  p_processes JSONB DEFAULT '[]'::jsonb,
  p_internet_state TEXT DEFAULT 'free',
  p_lockdown_state TEXT DEFAULT 'none',
  p_evaluation_id BIGINT DEFAULT NULL,
  p_app_version TEXT DEFAULT NULL
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_jwt_user TEXT;
BEGIN
  -- Guard de identidad-verificada (FASE 2): se EXIGE el claim verificado.
  -- Claim presente y DISTINTO del afirmado -> rechazo silencioso. Claim
  -- NULL/ausente (cliente sin enrolar) -> RECHAZADO (ya no es backward-compat).
  v_jwt_user := public.jwt_github_username();
  IF v_jwt_user IS NULL OR v_jwt_user = ''
     OR v_jwt_user IS DISTINCT FROM p_github_username THEN
    RETURN;
  END IF;

  INSERT INTO public.online_clients
    (pc_name, github_username, github_email, section, processes,
     internet_state, lockdown_state, evaluation_id, app_version, last_seen)
  VALUES
    (p_pc_name, p_github_username, p_github_email, p_section, p_processes,
     p_internet_state, p_lockdown_state, p_evaluation_id, p_app_version, NOW())
  ON CONFLICT (pc_name, github_username) DO UPDATE
  SET github_email   = EXCLUDED.github_email,
      section        = EXCLUDED.section,
      processes      = EXCLUDED.processes,
      internet_state = EXCLUDED.internet_state,
      lockdown_state = EXCLUDED.lockdown_state,
      evaluation_id  = COALESCE(EXCLUDED.evaluation_id, public.online_clients.evaluation_id),
      app_version    = COALESCE(EXCLUDED.app_version, public.online_clients.app_version),
      last_seen      = NOW();
END;
$$;

GRANT EXECUTE ON FUNCTION public.heartbeat(TEXT,TEXT,TEXT,TEXT,JSONB,TEXT,TEXT,BIGINT,TEXT)
  TO anon, authenticated;

-- ============================================================
--  VERIFICACION
--    1) La funcion heartbeat existe y es ejecutable por anon (firma/grant
--       intactos: exactamente UNA firma por nombre).
-- ============================================================

-- 1) heartbeat presente y ejecutable por anon (esperado: ok = true).
SELECT 'V1 heartbeat ejecutable por anon' AS check,
       has_function_privilege(
         'anon',
         'public.heartbeat(TEXT,TEXT,TEXT,TEXT,JSONB,TEXT,TEXT,BIGINT,TEXT)',
         'EXECUTE') AS ok;


-- ===== csharp/migration-targeted-read-scope.sql =====

-- ⚠️ FASE 2: EXIGE identidad verificada. RECHAZA clientes sin JWT (anon crudo).
-- NO CORRER hasta: (1) 0 clientes <2.7.20 activos (ENT-23) y (2) fuera de ventana de examen.
-- ============================================================
--  Migracion: TARGETED READ SCOPE -- FASE 2 (breaking: exige claim).
--  Idempotente. Correr en Supabase SQL Editor.
--
--  OBJETIVO (sec-backend-08, MEDIUM):
--  Hoy public.targeted_lockdowns expone UNA sola policy de lectura,
--  "anon_read_targeted", con:
--      FOR SELECT TO anon, authenticated USING (true)
--  Eso deja que CUALQUIER cliente con la apikey anon ENUMERE todas las
--  filas: que PCs / que alumnos estan bloqueados, sus reasons, etc.
--  (residual R3 documentado en migration-rls-identity-hardening.sql).
--
--  ARREGLO:
--  Partir esa lectura unica en DOS policies role-scoped, usando la
--  IDENTIDAD VERIFICADA del JWT (helper public.jwt_github_username(),
--  definido en migration-jwt-identity.sql: devuelve el claim verificado
--  o NULL si el cliente no esta enrolado / no manda JWT).
--
--    - targeted_read_teacher (TO authenticated, USING true):
--        el panel admin corre AUTHENTICATED y necesita ver TODAS las
--        filas (LockedStudentsSection). Queda intacto.
--
--    - targeted_read_student (TO anon, USING
--        github_username = jwt_github_username()):
--        el cliente enrolado solo ve SU propia fila (la consulta el con
--        GET filtrado por pc_name + github_username en SupabaseClient.cs:
--        IsTargetedLockedAsync / GetTargetedReasonAsync, nunca lista
--        todo). FASE 2: un cliente sin JWT (claim NULL, anon key cruda) ->
--        0 filas, deja de poder enumerar nada (ya NO hay backward-compat).
--
--  ALCANCE: esta migracion SOLO reemplaza la lectura anon de
--  targeted_lockdowns. NO toca INSERT/UPDATE/DELETE (auth_all_targeted,
--  ni la RPC report_self_lock que escribe via SECURITY DEFINER), NO toca
--  pc_overrides ni ninguna otra tabla/policy.
-- ============================================================


-- ============================================================
--  1. Reemplazo de la lectura anon amplia por dos policies
--     role-scoped. DROP IF EXISTS + CREATE para idempotencia.
-- ============================================================

-- Quita la policy vieja de lectura (anon + authenticated, USING true).
DROP POLICY IF EXISTS "anon_read_targeted" ON public.targeted_lockdowns;

-- Profe / panel admin: ve TODAS las filas (sesion authenticated).
DROP POLICY IF EXISTS "targeted_read_teacher" ON public.targeted_lockdowns;
CREATE POLICY "targeted_read_teacher" ON public.targeted_lockdowns
  FOR SELECT TO authenticated USING (true);

-- Cliente: SOLO ve su propia fila (FASE 2: se EXIGE el claim verificado; un
-- anon sin JWT -> jwt_github_username() NULL -> 0 filas, deja de ver todo).
DROP POLICY IF EXISTS "targeted_read_student" ON public.targeted_lockdowns;
CREATE POLICY "targeted_read_student" ON public.targeted_lockdowns
  FOR SELECT TO anon
  USING (github_username = public.jwt_github_username());


-- ============================================================
--  FASE 2 -- APLICADA EN ESTE ARCHIVO.
--  La policy targeted_read_student ya EXIGE identidad verificada: se
--  elimino la rama "claim NULL -> ve todo". Un anon sin JWT ->
--  jwt_github_username() NULL -> la comparacion da NULL -> 0 filas: deja de
--  poder enumerar nada. La policy del profe (targeted_read_teacher) queda
--  igual.
--
--  Precondicion para CORRERLO: TODOS los clientes enrolados con JWT (no
--  quedan clientes <2.7.20 activos, ENT-23) y fuera de ventana de examen.
--  Correrlo antes ciega a los clientes viejos sin JWT.
--
--  ROLLBACK A FASE 1 (backward-compat) si hay que revertir: reintroducir la
--  rama "claim NULL -> ve todo":
--    DROP POLICY IF EXISTS "targeted_read_student" ON public.targeted_lockdowns;
--    CREATE POLICY "targeted_read_student" ON public.targeted_lockdowns
--      FOR SELECT TO anon
--      USING (
--        public.jwt_github_username() IS NULL
--        OR github_username = public.jwt_github_username()
--      );
-- ============================================================


-- ============================================================
--  VERIFICACION
--     1) Existen las 2 policies role-scoped esperadas.
--     2) Ya NO queda ninguna policy de SELECT anon con USING(true)
--        sobre targeted_lockdowns (la enumeracion quedo cerrada).
--     3) (FASE 2) targeted_read_student ya NO contiene "IS NULL" en su qual
--        (se elimino la rama de backward-compat; esperado: 0 filas).
-- ============================================================

-- 1) Las 2 policies nuevas presentes con su rol correcto (esperado: 2 filas).
SELECT 'V1 policies role-scoped de lectura (esperado 2)' AS check,
       policyname, roles, qual
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename = 'targeted_lockdowns'
  AND cmd = 'SELECT'
  AND policyname IN ('targeted_read_teacher', 'targeted_read_student')
ORDER BY policyname;

-- 2) Ya no hay lectura anon abierta (esperado: 0 filas).
SELECT 'V2 lectura anon abierta residual (esperado 0)' AS check,
       policyname
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename = 'targeted_lockdowns'
  AND cmd = 'SELECT'
  AND 'anon' = ANY (roles)
  AND qual = 'true';

-- 3) (FASE 2) targeted_read_student sin rama "claim NULL" (esperado: 0 filas).
SELECT 'V3 targeted_read_student con IS NULL residual (esperado 0)' AS check,
       policyname
FROM pg_policies
WHERE schemaname = 'public'
  AND tablename = 'targeted_lockdowns'
  AND cmd = 'SELECT'
  AND policyname = 'targeted_read_student'
  AND qual ILIKE '%IS NULL%';

